import React, { useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './views/Dashboard';
import { Students } from './views/Students';
import { Financials } from './views/Financials';
import { MOCK_STUDENTS, MOCK_TEACHERS, MOCK_TRANSACTIONS } from './constants';
import { Student } from './types';

// Simple "About" view to fulfill Architecture Request visually
const ArchitectureInfo = () => (
  <div className="max-w-4xl mx-auto space-y-8 p-4">
    <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
      <h2 className="text-2xl font-bold text-slate-800 mb-4">هيكل النظام المقترح (System Architecture)</h2>
      <p className="text-slate-600 leading-relaxed mb-6">
        تم تصميم هذا النظام ليكون أساساً متيناً لنظام إدارة تعليمي Desktop-Class يعمل بتقنيات الويب الحديثة.
      </p>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="border p-4 rounded-xl border-slate-100">
          <h3 className="font-bold text-blue-600 mb-2">Frontend Layer (الواجهة)</h3>
          <ul className="list-disc list-inside text-sm text-slate-600 space-y-1">
            <li>React 18 مع TypeScript للأمان والمرونة.</li>
            <li>Tailwind CSS لتصميم حديث وسريع.</li>
            <li>Recharts للرسوم البيانية التفاعلية.</li>
            <li>تصميم متجاوب يعمل كـ PWA أو داخل Electron.</li>
          </ul>
        </div>

        <div className="border p-4 rounded-xl border-slate-100">
          <h3 className="font-bold text-purple-600 mb-2">Data Layer (البيانات)</h3>
          <ul className="list-disc list-inside text-sm text-slate-600 space-y-1">
            <li>Local-First Architecture: يعمل بدون إنترنت.</li>
            <li>يمكن استخدام SQLite أو PouchDB للتخزين المحلي.</li>
            <li>مزامنة خلفية (Background Sync) مع سحابة عند الاتصال.</li>
          </ul>
        </div>
      </div>
    </div>
  </div>
);

const App: React.FC = () => {
  const [activeView, setActiveView] = useState('dashboard');

  // Simulated State (In a real app, this would come from the Service Layer)
  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [transactions] = useState(MOCK_TRANSACTIONS);

  const handleAddStudent = (newStudent: Student) => {
    setStudents([...students, newStudent]);
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(students.filter(s => s.id !== id));
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard students={students} transactions={transactions} />;
      case 'students':
        return <Students students={students} onAddStudent={handleAddStudent} onDeleteStudent={handleDeleteStudent} />;
      case 'teachers':
        return <div className="p-8 text-center text-slate-500 bg-white rounded-2xl">واجهة إدارة المدرسين (قيد التطوير في النسخة التجريبية)</div>;
      case 'groups':
        return <div className="p-8 text-center text-slate-500 bg-white rounded-2xl">واجهة إدارة المجموعات والجداول (قيد التطوير في النسخة التجريبية)</div>;
      case 'financials':
        return <Financials transactions={transactions} />;
      case 'settings':
        return <ArchitectureInfo />;
      default:
        return <Dashboard students={students} transactions={transactions} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      {/* Main Content Area */}
      <main className="flex-1 mr-64 h-screen overflow-y-auto p-8 relative">
        <header className="flex justify-between items-center mb-8">
          <div>
             {/* Breadcrumbs or Title could go here */}
          </div>
          <div className="flex items-center gap-4">
             <div className="text-left hidden md:block">
                <p className="text-sm font-bold text-slate-700">أحمد المدير</p>
                <p className="text-xs text-slate-500">آخر ظهور: منذ دقيقتين</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
                <img src="https://picsum.photos/100/100" alt="Admin" />
             </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
           {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

