import React, { useState } from 'react';
import { 
  Users, 
  Calendar, 
  CheckCircle, 
  XCircle, 
  Clock, 
  ChevronRight, 
  Plus,
  Play,
  ArrowRight
} from 'lucide-react';
import { Group, Session, Student, AttendanceRecord, AttendanceStatus } from '../types';

interface GroupsProps {
  groups: Group[];
  students: Student[];
  sessions: Session[];
  attendance: AttendanceRecord[];
  onAddSession: (session: Session) => void;
  onUpdateAttendance: (record: AttendanceRecord) => void;
}

export const Groups: React.FC<GroupsProps> = ({ 
  groups, 
  students, 
  sessions, 
  attendance,
  onAddSession,
  onUpdateAttendance
}) => {
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);

  // Helper to get group details
  const selectedGroup = groups.find(g => g.id === selectedGroupId);

  // Helper to get sessions for selected group
  const groupSessions = sessions.filter(s => s.groupId === selectedGroupId);

  // Helper to get session details
  const selectedSession = sessions.find(s => s.id === selectedSessionId);

  // Navigation handlers
  const handleGroupClick = (id: string) => setSelectedGroupId(id);
  const handleBackToGroups = () => {
    setSelectedGroupId(null);
    setSelectedSessionId(null);
  };
  const handleSessionClick = (id: string) => setSelectedSessionId(id);
  const handleBackToSessions = () => setSelectedSessionId(null);

  // Create new session handler
  const handleCreateSession = () => {
    if (!selectedGroupId) return;
    const newSession: Session = {
      id: Date.now().toString(),
      groupId: selectedGroupId,
      date: new Date().toISOString().split('T')[0],
      startTime: new Date().toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit" }),
      status: 'active',
      topic: 'حصة جديدة'
    };
    onAddSession(newSession);
    setSelectedSessionId(newSession.id);
  };

  // Attendance handlers
  const markAttendance = (studentId: string, status: AttendanceStatus) => {
    if (!selectedSessionId) return;

    // Check if record exists
    const existingRecord = attendance.find(
      a => a.sessionId === selectedSessionId && a.studentId === studentId
    );

    const record: AttendanceRecord = {
      id: existingRecord ? existingRecord.id : Date.now().toString() + Math.random(),
      sessionId: selectedSessionId,
      studentId: studentId,
      status: status,
      timestamp: new Date().toISOString()
    };

    onUpdateAttendance(record);
  };

  const markAllPresent = () => {
    if (!selectedGroup) return;
    selectedGroup.studentIds.forEach(sid => {
      markAttendance(sid, 'present');
    });
  };

  // Render Functions
  const renderGroupList = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">المجموعات الدراسية</h2>
          <p className="text-slate-500 mt-1">اختر مجموعة لعرض الحصص وتسجيل الحضور</p>
        </div>
        <button className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-medium flex items-center shadow-lg shadow-blue-600/20">
          <Plus size={20} className="ml-2" />
          مجموعة جديدة
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {groups.map(group => (
          <div 
            key={group.id}
            onClick={() => handleGroupClick(group.id)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md hover:border-blue-200 cursor-pointer transition-all group"
          >
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-blue-50 rounded-xl text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                <Users size={24} />
              </div>
              <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-medium">
                {group.studentIds.length} طلاب
              </span>
            </div>
            <h3 className="text-lg font-bold text-slate-800 mb-2">{group.name}</h3>
            <p className="text-slate-500 text-sm mb-4">{group.subject}</p>
            <div className="pt-4 border-t border-slate-50 flex items-center text-slate-500 text-sm">
              <Calendar size={16} className="ml-2" />
              {group.schedule}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderSessionList = () => (
    <div className="space-y-6">
      <div className="flex items-center gap-4 mb-6">
        <button onClick={handleBackToGroups} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
          <ArrowRight size={24} />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{selectedGroup?.name}</h2>
          <p className="text-slate-500 mt-1">سجل الحصص والحضور</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 mb-6 flex justify-between items-center">
        <div>
          <h3 className="font-bold text-slate-800 text-lg">بدء حصة جديدة</h3>
          <p className="text-slate-500 text-sm">سيتم تسجيل الحضور للحصة الحالية تلقائياً عند البدء</p>
        </div>
        <button 
          onClick={handleCreateSession}
          className="bg-emerald-600 hover:bg-emerald-700 text-white px-6 py-3 rounded-xl font-bold flex items-center shadow-lg shadow-emerald-600/20"
        >
          <Play size={20} className="ml-2 fill-current" />
          بدء الحصة الآن
        </button>
      </div>

      <h3 className="font-bold text-slate-700 mb-4">سجل الحصص السابقة</h3>
      <div className="space-y-4">
        {groupSessions.length === 0 && (
          <div className="text-center py-10 text-slate-400">لا توجد حصص مسجلة لهذه المجموعة</div>
        )}
        {groupSessions.map(session => (
          <div 
            key={session.id} 
            onClick={() => handleSessionClick(session.id)}
            className="bg-white p-4 rounded-xl border border-slate-100 hover:border-blue-300 cursor-pointer flex items-center justify-between transition-all"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-lg flex items-center justify-center font-bold text-white ${
                session.status === 'completed' ? 'bg-slate-400' : 'bg-green-500'
              }`}>
                {new Date(session.date).getDate()}
              </div>
              <div>
                <h4 className="font-bold text-slate-800">{session.topic || 'بدون عنوان'}</h4>
                <div className="flex items-center text-xs text-slate-500 mt-1">
                  <Calendar size={12} className="ml-1" /> {session.date}
                  <Clock size={12} className="ml-1 mr-3" /> {session.startTime}
                </div>
              </div>
            </div>
            <div className="flex items-center gap-4">
                <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                    session.status === 'active' ? 'bg-green-100 text-green-700' : 
                    session.status === 'completed' ? 'bg-slate-100 text-slate-600' : 'bg-blue-100 text-blue-700'
                }`}>
                    {session.status === 'active' ? 'نشطة الآن' : session.status === 'completed' ? 'منتهية' : 'مجدولة'}
                </span>
                <ChevronRight size={20} className="text-slate-300" />
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderAttendanceSheet = () => {
    if (!selectedGroup || !selectedSession) return null;

    // Filter students belonging to this group
    const groupStudents = students.filter(s => selectedGroup.studentIds.includes(s.id));

    // Calculate stats
    const presentCount = groupStudents.filter(s => 
      attendance.find(a => a.sessionId === selectedSessionId && a.studentId === s.id)?.status === 'present'
    ).length;

    return (
      <div className="space-y-6">
        <div className="flex items-center gap-4 mb-6">
          <button onClick={handleBackToSessions} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500">
            <ArrowRight size={24} />
          </button>
          <div>
            <h2 className="text-2xl font-bold text-slate-800">تسجيل الحضور</h2>
            <div className="flex items-center gap-2 mt-1 text-slate-500 text-sm">
                <span>{selectedGroup.name}</span>
                <span>•</span>
                <span>{selectedSession.date}</span>
            </div>
          </div>
        </div>

        {/* Stats & Actions */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-bold text-slate-800">قائمة الطلاب ({groupStudents.length})</h3>
                    <button 
                        onClick={markAllPresent}
                        className="text-blue-600 text-sm font-medium hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors"
                    >
                        تسجيل الجميع "حضور"
                    </button>
                </div>

                <div className="space-y-3">
                    {groupStudents.map(student => {
                        const record = attendance.find(a => a.sessionId === selectedSessionId && a.studentId === student.id);
                        const status = record?.status;

                        return (
                            <div key={student.id} className="flex items-center justify-between p-3 rounded-xl border border-slate-100 hover:bg-slate-50 transition-colors">
                                <div className="flex items-center gap-3">
                                    <div className="w-10 h-10 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-600 text-sm">
                                        {student.name.charAt(0)}
                                    </div>
                                    <div>
                                        <p className="font-semibold text-slate-800">{student.name}</p>
                                        <p className="text-xs text-slate-500">{student.phone}</p>
                                    </div>
                                </div>
                                <div className="flex gap-1 bg-slate-100 p-1 rounded-lg">
                                    <button 
                                        onClick={() => markAttendance(student.id, 'present')}
                                        className={`p-2 rounded-md transition-all ${status === 'present' ? 'bg-green-500 text-white shadow-sm' : 'text-slate-400 hover:text-green-600'}`}
                                        title="حاضر"
                                    >
                                        <CheckCircle size={20} />
                                    </button>
                                    <button 
                                        onClick={() => markAttendance(student.id, 'late')}
                                        className={`p-2 rounded-md transition-all ${status === 'late' ? 'bg-amber-500 text-white shadow-sm' : 'text-slate-400 hover:text-amber-600'}`}
                                        title="تأخير"
                                    >
                                        <Clock size={20} />
                                    </button>
                                    <button 
                                        onClick={() => markAttendance(student.id, 'absent')}
                                        className={`p-2 rounded-md transition-all ${status === 'absent' ? 'bg-rose-500 text-white shadow-sm' : 'text-slate-400 hover:text-rose-600'}`}
                                        title="غائب"
                                    >
                                        <XCircle size={20} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="space-y-6">
                <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                    <h3 className="font-bold text-slate-800 mb-4">ملخص الحضور</h3>
                    <div className="space-y-4">
                        <div className="flex justify-between items-center">
                            <span className="text-slate-600">حضور</span>
                            <span className="font-bold text-green-600">{presentCount}</span>
                        </div>
                         <div className="flex justify-between items-center">
                            <span className="text-slate-600">غياب</span>
                            <span className="font-bold text-rose-600">
                                {groupStudents.length - groupStudents.filter(s => attendance.find(a => a.sessionId === selectedSessionId && a.studentId === s.id)).length}
                            </span>
                        </div>
                        <div className="pt-4 border-t border-slate-100">
                            <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
                                <div 
                                    className="bg-green-500 h-2.5 rounded-full" 
                                    style={{ width: `${(presentCount / groupStudents.length) * 100}%` }}
                                ></div>
                            </div>
                            <p className="text-xs text-center mt-2 text-slate-500">نسبة الحضور: {Math.round((presentCount / groupStudents.length) * 100)}%</p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
      </div>
    );
  };

  if (selectedSessionId) return renderAttendanceSheet();
  if (selectedGroupId) return renderSessionList();
  return renderGroupList();
};

