const App: React.FC = () => {
  const [activeView, setActiveView] = useState('dashboard');

  // Simulated State (In a real app, this would come from the Service Layer)
  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [transactions] = useState(MOCK_TRANSACTIONS);
  const [groups] = useState(MOCK_GROUPS);
  const [sessions, setSessions] = useState<Session[]>(MOCK_SESSIONS);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>(MOCK_ATTENDANCE);

  const handleAddStudent = (newStudent: Student) => {
    setStudents([...students, newStudent]);
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(students.filter(s => s.id !== id));
  };

  const handleAddSession = (newSession: Session) => {
    setSessions([newSession, ...sessions]);
  };

  const handleUpdateAttendance = (record: AttendanceRecord) => {
    setAttendance(prev => {
      // Remove existing record for this student/session if it exists
      const filtered = prev.filter(a => !(a.sessionId === record.sessionId && a.studentId === record.studentId));
      return [...filtered, record];
    });
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard students={students} transactions={transactions} />;
      case 'students':
        return <Students students={students} onAddStudent={handleAddStudent} onDeleteStudent={handleDeleteStudent} />;
      case 'teachers':
        return <div className="p-8 text-center text-slate-500 bg-white rounded-2xl">واجهة إدارة المدرسين (قيد التطوير في النسخة التجريبية)</div>;
      case 'groups':
        return (
          <Groups 
            groups={groups} 
            students={students} 
            sessions={sessions} 
            attendance={attendance}
            onAddSession={handleAddSession}
            onUpdateAttendance={handleUpdateAttendance}
          />
        );
      case 'financials':
        return <Financials transactions={transactions} />;
      case 'settings':
        return <ArchitectureInfo />;
      default:
        return <Dashboard students={students} transactions={transactions} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      {/* Main Content Area */}
      <main className="flex-1 mr-64 h-screen overflow-y-auto p-8 relative">
        <header className="flex justify-between items-center mb-8">
          <div>
             {/* Breadcrumbs or Title could go here */}
          </div>
          <div className="flex items-center gap-4">
             <div className="text-left hidden md:block">
                <p className="text-sm font-bold text-slate-700">أحمد المدير</p>
                <p className="text-xs text-slate-500">آخر ظهور: منذ دقيقتين</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
                <img src="https://picsum.photos/100/100" alt="Admin" />
             </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
           {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  Users, 
  Calendar, 
  CheckCircle, 
  XCircle, 
  Clock, 
  ChevronRight, 
  Plus,
  Play,
  ArrowRight,
  X,
  FileText,
  Filter,
  MoreVertical
} from 'lucide-react';
import { Group, Session, Student, AttendanceRecord, AttendanceStatus } from '../types';

interface GroupsProps {
  groups: Group[];
  students: Student[];
  sessions: Session[];
  attendance: AttendanceRecord[];
  onAddSession: (session: Session) => void;
  onUpdateAttendance: (record: AttendanceRecord) => void;
}

export const Groups: React.FC<GroupsProps> = ({ 
  groups, 
  students, 
  sessions, 
  attendance,
  onAddSession,
  onUpdateAttendance
}) => {
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);

  // Scheduling Modal State
  const [isScheduleModalOpen, setIsScheduleModalOpen] = useState(false);
  const [sessionFormData, setSessionFormData] = useState({
    topic: '',
    date: new Date().toISOString().split('T')[0],
    startTime: '16:00'
  });

  // Session List View State
  const [activeTab, setActiveTab] = useState<'upcoming' | 'history'>('upcoming');

  // Helpers
  const selectedGroup = groups.find(g => g.id === selectedGroupId);
  const groupSessions = sessions.filter(s => s.groupId === selectedGroupId);
  const selectedSession = sessions.find(s => s.id === selectedSessionId);

  // Computed Lists
  const upcomingSessions = groupSessions
    .filter(s => s.status !== 'completed')
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  const historySessions = groupSessions
    .filter(s => s.status === 'completed')
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Navigation handlers
  const handleGroupClick = (id: string) => setSelectedGroupId(id);
  const handleBackToGroups = () => {
    setSelectedGroupId(null);
    setSelectedSessionId(null);
    setActiveTab('upcoming');
  };
  const handleSessionClick = (id: string) => setSelectedSessionId(id);
  const handleBackToSessions = () => setSelectedSessionId(null);

  // Session Management
  const handleQuickStartSession = () => {
    if (!selectedGroupId) return;
    const newSession: Session = {
      id: Date.now().toString(),
      groupId: selectedGroupId,
      date: new Date().toISOString().split('T')[0],
      startTime: new Date().toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit" }),
      status: 'active',
      topic: 'حصة جديدة - ' + new Date().toLocaleDateString('ar-EG')
    };
    onAddSession(newSession);
    setSelectedSessionId(newSession.id);
  };

  const handleScheduleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedGroupId) return;

    const newSession: Session = {
      id: Date.now().toString(),
      groupId: selectedGroupId,
      date: sessionFormData.date,
      startTime: sessionFormData.startTime,
      status: 'scheduled',
      topic: sessionFormData.topic
    };

    onAddSession(newSession);
    setIsScheduleModalOpen(false);
    setSessionFormData({
      topic: '',
      date: new Date().toISOString().split('T')[0],
      startTime: '16:00'
    });
  };

  // Attendance handlers
  const markAttendance = (studentId: string, status: AttendanceStatus) => {
    if (!selectedSessionId) return;

    const existingRecord = attendance.find(
      a => a.sessionId === selectedSessionId && a.studentId === studentId
    );

    const record: AttendanceRecord = {
      id: existingRecord ? existingRecord.id : Date.now().toString() + Math.random(),
      sessionId: selectedSessionId,
      studentId: studentId,
      status: status,
      timestamp: new Date().toISOString()
    };

    onUpdateAttendance(record);
  };

  const markAllPresent = () => {
    if (!selectedGroup) return;
    selectedGroup.studentIds.forEach(sid => {
      markAttendance(sid, 'present');
    });
  };

  // --- Render Sections ---

  const renderGroupList = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">المجموعات الدراسية</h2>
          <p className="text-slate-500 mt-1">إدارة الحصص، الجداول، وتسجيل الحضور</p>
        </div>
        <button className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-medium flex items-center shadow-lg shadow-blue-600/20">
          <Plus size={20} className="ml-2" />
          مجموعة جديدة
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {groups.map(group => (
          <div 
            key={group.id}
            onClick={() => handleGroupClick(group.id)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md hover:border-blue-200 cursor-pointer transition-all group"
          >
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-blue-50 rounded-xl text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                <Users size={24} />
              </div>
              <div className="flex flex-col items-end">
                <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-medium">
                    {group.studentIds.length} طلاب
                </span>
              </div>
            </div>
            <h3 className="text-lg font-bold text-slate-800 mb-2">{group.name}</h3>
            <p className="text-slate-500 text-sm mb-4">{group.subject}</p>
            <div className="pt-4 border-t border-slate-50 flex items-center text-slate-500 text-sm">
              <Calendar size={16} className="ml-2" />
              {group.schedule}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderSessionList = () => (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <button onClick={handleBackToGroups} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors">
          <ArrowRight size={24} />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{selectedGroup?.name}</h2>
          <p className="text-slate-500 mt-1">إدارة الحصص والجداول</p>
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex flex-col md:flex-row gap-4">
        <button 
            onClick={handleQuickStartSession}
            className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white p-4 rounded-xl font-bold flex items-center justify-center shadow-lg shadow-emerald-600/20 transition-all"
        >
            <Play size={20} className="ml-2 fill-current" />
            بدء حصة فورية
        </button>
        <button 
            onClick={() => setIsScheduleModalOpen(true)}
            className="flex-1 bg-white border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50 text-slate-600 p-4 rounded-xl font-medium flex items-center justify-center transition-all"
        >
            <Calendar size={20} className="ml-2" />
            جدولة حصة جديدة
        </button>
      </div>

      {/* Tabs */}
      <div className="border-b border-slate-200 mt-6">
        <div className="flex gap-6">
            <button 
                onClick={() => setActiveTab('upcoming')}
                className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'upcoming' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                الحصص القادمة / النشطة
                {activeTab === 'upcoming' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
            <button 
                 onClick={() => setActiveTab('history')}
                 className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'history' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                سجل الحصص السابقة
                {activeTab === 'history' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
        </div>
      </div>

      {/* List */}
      <div className="space-y-4 min-h-[300px]">
        {(activeTab === 'upcoming' ? upcomingSessions : historySessions).length === 0 && (
          <div className="text-center py-16 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
            <div className="w-12 h-12 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-3 text-slate-400">
                <FileText size={24} />
            </div>
            <p className="text-slate-500">لا توجد حصص في هذه القائمة</p>
          </div>
        )}

        {(activeTab === 'upcoming' ? upcomingSessions : historySessions).map(session => (
          <div 
            key={session.id} 
            onClick={() => handleSessionClick(session.id)}
            className="bg-white p-4 rounded-xl border border-slate-100 hover:border-blue-300 hover:shadow-sm cursor-pointer flex items-center justify-between transition-all"
          >
            <div className="flex items-center gap-4">
              <div className={`w-14 h-14 rounded-xl flex flex-col items-center justify-center font-bold text-white shadow-sm ${
                session.status === 'completed' ? 'bg-slate-500' : 
