  const renderAttendanceSheet = () => {
    if (!selectedGroup || !selectedSession) return null;

    const groupStudents = students.filter(s => selectedGroup.studentIds.includes(s.id));
    const presentCount = groupStudents.filter(s => 
      attendance.find(a => a.sessionId === selectedSessionId && a.studentId === s.id)?.status === 'present'
