                </div>

                <div className="bg-blue-50 rounded-2xl border border-blue-100 p-4">
                    <h4 className="font-bold text-blue-800 text-sm mb-2">ملاحظة سريعة</h4>
                    <p className="text-xs text-blue-600 leading-relaxed">
                        تأكد من حفظ أي ملاحظات إضافية حول سلوك الطلاب في قسم الملاحظات (قيد التطوير).
                    </p>
                </div>
            </div>
        </div>
      </div>
    );
  };

  if (selectedSessionId) return renderAttendanceSheet();
  if (selectedGroupId) return renderSessionList();
  return renderGroupList();
};

