const App: React.FC = () => {
  const [activeView, setActiveView] = useState('dashboard');

  // Simulated State (In a real app, this would come from the Service Layer)
  const [students, setStudents] = useState<Student[]>(MOCK_STUDENTS);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);
  const [groups] = useState(MOCK_GROUPS);
  const [sessions, setSessions] = useState<Session[]>(MOCK_SESSIONS);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>(MOCK_ATTENDANCE);

  const handleAddStudent = (newStudent: Student) => {
    setStudents([...students, newStudent]);
  };

  const handleDeleteStudent = (id: string) => {
    setStudents(students.filter(s => s.id !== id));
  };

  const handleAddSession = (newSession: Session) => {
    setSessions([newSession, ...sessions]);
  };

  const handleUpdateSession = (updatedSession: Session) => {
    setSessions(sessions.map(s => s.id === updatedSession.id ? updatedSession : s));
  };

  const handleUpdateAttendance = (record: AttendanceRecord) => {
    setAttendance(prev => {
      // Remove existing record for this student/session if it exists
      const filtered = prev.filter(a => !(a.sessionId === record.sessionId && a.studentId === record.studentId));
      return [...filtered, record];
    });
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    setTransactions([newTransaction, ...transactions]);

    // Update Student Balance logic
    if (newTransaction.studentId) {
        setStudents(prevStudents => prevStudents.map(student => {
            if (student.id === newTransaction.studentId) {
                // Income means student paid money -> Balance increases (Credit)
                // Expense means refund -> Balance decreases
                const change = newTransaction.type === 'income' ? newTransaction.amount : -newTransaction.amount;
                return { ...student, balance: student.balance + change };
            }
            return student;
        }));
    }
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard students={students} transactions={transactions} />;
      case 'students':
        return (
            <Students 
                students={students} 
                transactions={transactions}
                onAddStudent={handleAddStudent} 
                onDeleteStudent={handleDeleteStudent}
                onAddTransaction={handleAddTransaction}
            />
        );
      case 'teachers':
        return <div className="p-8 text-center text-slate-500 bg-white rounded-2xl">واجهة إدارة المدرسين (قيد التطوير في النسخة التجريبية)</div>;
      case 'groups':
        return (
          <Groups 
            groups={groups} 
            students={students} 
            sessions={sessions} 
            attendance={attendance}
            onAddSession={handleAddSession}
            onUpdateSession={handleUpdateSession}
            onUpdateAttendance={handleUpdateAttendance}
          />
        );
      case 'financials':
        return <Financials transactions={transactions} />;
      case 'settings':
        return <ArchitectureInfo />;
      default:
        return <Dashboard students={students} transactions={transactions} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      {/* Main Content Area */}
      <main className="flex-1 mr-64 h-screen overflow-y-auto p-8 relative">
        <header className="flex justify-between items-center mb-8">
          <div>
             {/* Breadcrumbs or Title could go here */}
          </div>
          <div className="flex items-center gap-4">
             <div className="text-left hidden md:block">
                <p className="text-sm font-bold text-slate-700">أحمد المدير</p>
                <p className="text-xs text-slate-500">آخر ظهور: منذ دقيقتين</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
                <img src="https://picsum.photos/100/100" alt="Admin" />
             </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
           {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  Users, 
  Calendar as CalendarIcon, 
  CheckCircle, 
  XCircle, 
  Clock, 
  ChevronRight, 
  ChevronLeft,
  Plus,
  Play,
  ArrowRight,
  X,
  FileText,
  Filter,
  MoreVertical,
  List,
  Edit2
} from 'lucide-react';
import { Group, Session, Student, AttendanceRecord, AttendanceStatus } from '../types';

interface GroupsProps {
  groups: Group[];
  students: Student[];
  sessions: Session[];
  attendance: AttendanceRecord[];
  onAddSession: (session: Session) => void;
  onUpdateSession: (session: Session) => void;
  onUpdateAttendance: (record: AttendanceRecord) => void;
}

export const Groups: React.FC<GroupsProps> = ({ 
  groups, 
  students, 
  sessions, 
  attendance,
  onAddSession,
  onUpdateSession,
  onUpdateAttendance
}) => {
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);

  // Scheduling/Editing Modal State
  const [isScheduleModalOpen, setIsScheduleModalOpen] = useState(false);
  const [editingSessionId, setEditingSessionId] = useState<string | null>(null);
  const [sessionFormData, setSessionFormData] = useState({
    topic: '',
    date: new Date().toISOString().split('T')[0],
    startTime: '16:00'
  });

  // Session List View State
  const [activeTab, setActiveTab] = useState<'upcoming' | 'history'>('upcoming');
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('list');
  const [calendarDate, setCalendarDate] = useState(new Date());

  // Helpers
  const selectedGroup = groups.find(g => g.id === selectedGroupId);
  const groupSessions = sessions.filter(s => s.groupId === selectedGroupId);
  const selectedSession = sessions.find(s => s.id === selectedSessionId);

  // Computed Lists
  const upcomingSessions = groupSessions
    .filter(s => s.status !== 'completed')
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  const historySessions = groupSessions
    .filter(s => s.status === 'completed')
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Navigation handlers
  const handleGroupClick = (id: string) => setSelectedGroupId(id);
  const handleBackToGroups = () => {
    setSelectedGroupId(null);
    setSelectedSessionId(null);
    setActiveTab('upcoming');
    setViewMode('list');
  };
  const handleSessionClick = (id: string) => setSelectedSessionId(id);
  const handleBackToSessions = () => setSelectedSessionId(null);

  // Session Management
  const handleQuickStartSession = () => {
    if (!selectedGroupId) return;
    const newSession: Session = {
      id: Date.now().toString(),
      groupId: selectedGroupId,
      date: new Date().toISOString().split('T')[0],
      startTime: new Date().toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit" }),
      status: 'active',
      topic: 'حصة جديدة - ' + new Date().toLocaleDateString('ar-EG')
    };
    onAddSession(newSession);
    setSelectedSessionId(newSession.id);
  };

  const openScheduleModal = (date?: string, sessionToEdit?: Session) => {
    if (sessionToEdit) {
      setEditingSessionId(sessionToEdit.id);
      setSessionFormData({
        topic: sessionToEdit.topic || '',
        date: sessionToEdit.date,
        startTime: sessionToEdit.startTime
      });
    } else {
      setEditingSessionId(null);
      setSessionFormData({
        topic: '',
        date: date || new Date().toISOString().split('T')[0],
        startTime: '16:00'
      });
    }
    setIsScheduleModalOpen(true);
  };

  const handleScheduleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedGroupId) return;

    if (editingSessionId) {
       // Update existing session
       const sessionToUpdate = sessions.find(s => s.id === editingSessionId);
       if (sessionToUpdate) {
          const updatedSession: Session = {
             ...sessionToUpdate,
             topic: sessionFormData.topic,
             date: sessionFormData.date,
             startTime: sessionFormData.startTime
          };
          onUpdateSession(updatedSession);
       }
    } else {
       // Create new session
       const newSession: Session = {
        id: Date.now().toString(),
        groupId: selectedGroupId,
        date: sessionFormData.date,
        startTime: sessionFormData.startTime,
        status: 'scheduled',
        topic: sessionFormData.topic
      };
      onAddSession(newSession);
    }

    setIsScheduleModalOpen(false);
  };

  // Calendar Logic
  const changeMonth = (offset: number) => {
    const newDate = new Date(calendarDate);
    newDate.setMonth(newDate.getMonth() + offset);
    setCalendarDate(newDate);
  };

  const getDaysInMonth = (date: Date) => {
    return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  };

  const getFirstDayOfMonth = (date: Date) => {
    return new Date(date.getFullYear(), date.getMonth(), 1).getDay();
  };

  // Attendance handlers
  const markAttendance = (studentId: string, status: AttendanceStatus) => {
    if (!selectedSessionId) return;

    const existingRecord = attendance.find(
      a => a.sessionId === selectedSessionId && a.studentId === studentId
    );

    const record: AttendanceRecord = {
      id: existingRecord ? existingRecord.id : Date.now().toString() + Math.random(),
      sessionId: selectedSessionId,
      studentId: studentId,
      status: status,
      timestamp: new Date().toISOString()
    };

    onUpdateAttendance(record);
  };

  const markAllPresent = () => {
    if (!selectedGroup) return;
    selectedGroup.studentIds.forEach(sid => {
      markAttendance(sid, 'present');
    });
  };

  // --- Render Sections ---

  const renderGroupList = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">المجموعات الدراسية</h2>
          <p className="text-slate-500 mt-1">إدارة الحصص، الجداول، وتسجيل الحضور</p>
        </div>
        <button className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-medium flex items-center shadow-lg shadow-blue-600/20">
          <Plus size={20} className="ml-2" />
          مجموعة جديدة
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {groups.map(group => (
          <div 
            key={group.id}
            onClick={() => handleGroupClick(group.id)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md hover:border-blue-200 cursor-pointer transition-all group"
          >
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-blue-50 rounded-xl text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                <Users size={24} />
              </div>
              <div className="flex flex-col items-end">
                <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-full text-xs font-medium">
                    {group.studentIds.length} طلاب
                </span>
              </div>
            </div>
            <h3 className="text-lg font-bold text-slate-800 mb-2">{group.name}</h3>
            <p className="text-slate-500 text-sm mb-4">{group.subject}</p>
            <div className="pt-4 border-t border-slate-50 flex items-center text-slate-500 text-sm">
              <CalendarIcon size={16} className="ml-2" />
              {group.schedule}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderCalendar = () => {
    const daysInMonth = getDaysInMonth(calendarDate);
    const firstDay = getFirstDayOfMonth(calendarDate); 

    // Sat=0, Sun=1... Fri=6
    const startOffset = (firstDay + 1) % 7; 

    const days = [];
    const emptyDays = Array(startOffset).fill(null);
    const actualDays = Array.from({ length: daysInMonth }, (_, i) => i + 1);

    const weekDays = ['السبت', 'الأحد', 'الاثنين', 'الثلاثاء', 'الأربعاء', 'الخميس', 'الجمعة'];

    const currentYear = calendarDate.getFullYear();
    const currentMonth = calendarDate.getMonth();

    return (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 animate-in fade-in zoom-in duration-300">
            {/* Calendar Header */}
            <div className="flex justify-between items-center mb-6">
                <div className="flex items-center gap-4">
                    <h3 className="text-xl font-bold text-slate-800">
                        {calendarDate.toLocaleDateString('ar-EG', { month: 'long', year: 'numeric' })}
                    </h3>
                    <div className="flex bg-slate-100 rounded-lg p-1">
                        <button onClick={() => changeMonth(-1)} className="p-1 hover:bg-white rounded-md transition-all shadow-sm">
                            <ChevronRight size={20} className="text-slate-600"/>
                        </button>
                        <button onClick={() => changeMonth(1)} className="p-1 hover:bg-white rounded-md transition-all shadow-sm">
                            <ChevronLeft size={20} className="text-slate-600"/>
                        </button>
                    </div>
                </div>
                <button 
                    onClick={() => openScheduleModal()}
                    className="text-sm bg-blue-50 text-blue-600 px-3 py-1.5 rounded-lg font-medium hover:bg-blue-100 transition-colors"
                >
                    إضافة حدث
                </button>
            </div>

            {/* Grid Header */}
            <div className="grid grid-cols-7 mb-2">
                {weekDays.map(day => (
                    <div key={day} className="text-center text-sm font-medium text-slate-400 py-2">
                        {day}
                    </div>
                ))}
            </div>

            {/* Grid Body */}
            <div className="grid grid-cols-7 gap-2">
                {emptyDays.map((_, index) => (
                    <div key={`empty-${index}`} className="h-28 bg-slate-50/50 rounded-xl border border-transparent"></div>
                ))}
                {actualDays.map(day => {
                    const dateStr = `${currentYear}-${String(currentMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                    const daySessions = groupSessions.filter(s => s.date === dateStr);
                    const isToday = new Date().toISOString().split('T')[0] === dateStr;

                    return (
                        <div 
                            key={day} 
                            onClick={() => openScheduleModal(dateStr)}
                            className={`h-28 border rounded-xl p-2 relative group hover:border-blue-400 transition-all cursor-pointer ${
                                isToday ? 'bg-blue-50/30 border-blue-200' : 'bg-white border-slate-100'
                            }`}
                        >
                            <span className={`text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full ${
                                isToday ? 'bg-blue-600 text-white' : 'text-slate-600 group-hover:bg-slate-100'
                            }`}>
                                {day}
                            </span>

                            <div className="mt-2 space-y-1 overflow-y-auto max-h-[calc(100%-32px)]">
                                {daySessions.map(session => (
                                    <div 
                                        key={session.id}
                                        onClick={(e) => { e.stopPropagation(); handleSessionClick(session.id); }}
                                        className={`text-[10px] p-1.5 rounded-md truncate border-l-2 cursor-pointer transition-colors ${
                                            session.status === 'completed' 
                                            ? 'bg-slate-100 border-slate-400 text-slate-600'
                                            : session.status === 'active'
                                            ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-medium'
                                            : 'bg-blue-50 border-blue-500 text-blue-700'
                                        }`}
                                    >
                                        {session.topic || 'حصة'}
                                    </div>
                                ))}
                            </div>

                            {/* Hover Add Icon */}
                            <div className="absolute top-2 left-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                <div className="w-6 h-6 bg-blue-100 rounded-full flex items-center justify-center text-blue-600">
                                    <Plus size={14} />
                                </div>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  const renderSessionList = () => (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <button onClick={handleBackToGroups} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors">
          <ArrowRight size={24} />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{selectedGroup?.name}</h2>
          <p className="text-slate-500 mt-1">إدارة الحصص والجداول</p>
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex flex-col md:flex-row gap-4">
        <button 
            onClick={handleQuickStartSession}
            className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white p-4 rounded-xl font-bold flex items-center justify-center shadow-lg shadow-emerald-600/20 transition-all"
        >
            <Play size={20} className="ml-2 fill-current" />
            بدء حصة فورية
        </button>
        <button 
            onClick={() => openScheduleModal()}
            className="flex-1 bg-white border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50 text-slate-600 p-4 rounded-xl font-medium flex items-center justify-center transition-all"
        >
            <CalendarIcon size={20} className="ml-2" />
            جدولة حصة جديدة
        </button>
      </div>

      {/* View Toggle & Tabs */}
      <div className="flex flex-col sm:flex-row justify-between items-center border-b border-slate-200 mt-6 gap-4">
        <div className="flex gap-6 w-full sm:w-auto">
            <button 
                onClick={() => setActiveTab('upcoming')}
                className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'upcoming' && viewMode === 'list' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
                disabled={viewMode === 'calendar'}
            >
                الحصص القادمة
                {activeTab === 'upcoming' && viewMode === 'list' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
            <button 
                 onClick={() => setActiveTab('history')}
                 className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'history' && viewMode === 'list' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
                disabled={viewMode === 'calendar'}
            >
                سجل الحصص السابقة
                {activeTab === 'history' && viewMode === 'list' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-lg mb-2 sm:mb-0">
            <button 
                onClick={() => setViewMode('list')}
                className={`p-2 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${
                    viewMode === 'list' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                <List size={16} />
                قائمة
            </button>
            <button 
                onClick={() => setViewMode('calendar')}
                className={`p-2 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${
                    viewMode === 'calendar' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                <CalendarIcon size={16} />
                تقويم
            </button>
        </div>
      </div>

      {/* Content Area */}
      {viewMode === 'calendar' ? (
          renderCalendar()
      ) : (
          <div className="space-y-4 min-h-[300px] animate-in fade-in slide-in-from-bottom-2 duration-300">
            {(activeTab === 'upcoming' ? upcomingSessions : historySessions).length === 0 && (
            <div className="text-center py-16 bg-slate-50 rounded-2xl border-2 border-dashed border-slate-200">
                <div className="w-12 h-12 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-3 text-slate-400">
                    <FileText size={24} />
                </div>
                <p className="text-slate-500">لا توجد حصص في هذه القائمة</p>
            </div>
            )}

            {(activeTab === 'upcoming' ? upcomingSessions : historySessions).map(session => (
            <div 
                key={session.id} 
                onClick={() => handleSessionClick(session.id)}
                className="bg-white p-4 rounded-xl border border-slate-100 hover:border-blue-300 hover:shadow-sm cursor-pointer flex items-center justify-between transition-all group"
            >
                <div className="flex items-center gap-4">
                <div className={`w-14 h-14 rounded-xl flex flex-col items-center justify-center font-bold text-white shadow-sm ${
                    session.status === 'completed' ? 'bg-slate-500' : 
                    session.status === 'active' ? 'bg-emerald-500' : 'bg-blue-500'
                }`}>
                    <span className="text-lg leading-none">{new Date(session.date).getDate()}</span>
                    <span className="text-[10px] font-normal opacity-80 mt-1">
                        {new Date(session.date).toLocaleDateString('ar-EG', { month: 'short' })}
                    </span>
                </div>
                <div>
                    <h4 className="font-bold text-slate-800 text-lg">{session.topic || 'بدون عنوان'}</h4>
                    <div className="flex items-center text-sm text-slate-500 mt-1">
                    <Clock size={14} className="ml-1" /> 
                    {session.startTime}
                    <span className="mx-2 text-slate-300">|</span>
                    <span className={`${
                        session.status === 'active' ? 'text-emerald-600 font-medium' : ''
                    }`}>
                        {session.status === 'active' ? 'جارية الآن' : 
                        session.status === 'scheduled' ? 'مجدولة' : 'منتهية'}
                    </span>
                    </div>
                </div>
                </div>
                <div className="flex items-center gap-2">
                     <button
                        onClick={(e) => { e.stopPropagation(); openScheduleModal(undefined, session); }}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors opacity-0 group-hover:opacity-100"
                        title="تعديل الموعد"
                    >
                        <Edit2 size={18} />
                    </button>
                    {session.status === 'active' && (
                        <span className="animate-pulse w-2 h-2 rounded-full bg-emerald-500 mr-2"></span>
                    )}
                    <ChevronRight size={20} className="text-slate-300" />
                </div>
            </div>
            ))}
        </div>
      )}

       {/* Schedule Modal */}
       {isScheduleModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">
                  {editingSessionId ? 'تعديل موعد الحصة' : 'جدولة حصة جديدة'}
              </h3>
              <button onClick={() => setIsScheduleModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
            </div>
            <form onSubmit={handleScheduleSubmit} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">موضوع الحصة</label>
                <input 
                  required
                  placeholder="مثال: مراجعة الوحدة الأولى"
                  className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={sessionFormData.topic}
                  onChange={e => setSessionFormData({...sessionFormData, topic: e.target.value})}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                 <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">التاريخ</label>
                  <input 
                    type="date"
                    required
                    className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    value={sessionFormData.date}
                    onChange={e => setSessionFormData({...sessionFormData, date: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">الوقت</label>
                  <input 
                    type="time"
                    required
                    className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    value={sessionFormData.startTime}
                    onChange={e => setSessionFormData({...sessionFormData, startTime: e.target.value})}
                  />
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  type="submit" 
                  className="flex-1 bg-blue-600 text-white py-2.5 rounded-lg font-medium hover:bg-blue-700 transition-colors"
                >
                  {editingSessionId ? 'حفظ التعديلات' : 'حفظ الحصة'}
                </button>
                <button 
                  type="button" 
                  onClick={() => setIsScheduleModalOpen(false)}
                  className="flex-1 bg-slate-100 text-slate-600 py-2.5 rounded-lg font-medium hover:bg-slate-200 transition-colors"
                >
                  إلغاء
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );

  const renderAttendanceSheet = () => {
    if (!selectedGroup || !selectedSession) return null;

    const groupStudents = students.filter(s => selectedGroup.studentIds.includes(s.id));
    const presentCount = groupStudents.filter(s => 
      attendance.find(a => a.sessionId === selectedSessionId && a.studentId === s.id)?.status === 'present'
    ).length;

    return (
      <div className="space-y-6">
        <div className="flex items-center gap-4 mb-6">
          <button onClick={handleBackToSessions} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors">
            <ArrowRight size={24} />
          </button>
          <div className="flex-1">
            <div className="flex items-center gap-3">
                <h2 className="text-2xl font-bold text-slate-800">تسجيل الحضور</h2>
                <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                    selectedSession.status === 'active' ? 'bg-green-100 text-green-700' : 
                    selectedSession.status === 'completed' ? 'bg-slate-100 text-slate-600' : 'bg-blue-100 text-blue-700'
                }`}>
