                            <span className="font-bold text-slate-800">
                                {groupStudents.length - groupStudents.filter(s => attendance.find(a => a.sessionId === selectedSessionId && a.studentId === s.id)).length}
                            </span>
                        </div>
                        <div className="pt-4 border-t border-slate-100">
                            <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
                                <div 
                                    className="bg-emerald-500 h-2.5 rounded-full transition-all duration-500" 
                                    style={{ width: `${groupStudents.length > 0 ? (presentCount / groupStudents.length) * 100 : 0}%` }}
                                ></div>
                            </div>
                            <p className="text-xs text-center mt-2 text-slate-500">
                                نسبة الحضور: {groupStudents.length > 0 ? Math.round((presentCount / groupStudents.length) * 100) : 0}%
                            </p>
                        </div>
                    </div>
                </div>

                <div className="bg-blue-50 rounded-2xl border border-blue-100 p-4">
                    <h4 className="font-bold text-blue-800 text-sm mb-2">ملاحظة سريعة</h4>
                    <p className="text-xs text-blue-600 leading-relaxed">
                        تأكد من حفظ أي ملاحظات إضافية حول سلوك الطلاب في قسم الملاحظات (قيد التطوير).
                    </p>
                </div>
            </div>
        </div>
      </div>
    );
  };

  if (selectedSessionId) return renderAttendanceSheet();
  if (selectedGroupId) return renderSessionList();
  return renderGroupList();
};

import React, { useState, useEffect } from 'react';
import { X } from 'lucide-react';
