import React from 'react';
import { Transaction } from '../types';
import { CURRENCY } from '../constants';
import { TrendingUp, TrendingDown, Calendar, FileSpreadsheet } from 'lucide-react';

interface FinancialsProps {
  transactions: Transaction[];
}

export const Financials: React.FC<FinancialsProps> = ({ transactions }) => {

  const handleExportExcel = () => {
    // Define headers
    const headers = ['التاريخ', 'الوصف', 'التصنيف', 'النوع', 'المبلغ', 'ملاحظات'];

    // Helper to escape CSV fields (handle commas and quotes)
    const escapeCsv = (field: string | number | undefined) => {
      if (field === undefined || field === null) return '""';
      const stringField = String(field);
      if (stringField.includes(',') || stringField.includes('"') || stringField.includes('\n')) {
        return `"${stringField.replace(/"/g, '""')}"`;
      }
      return stringField;
    };

    // Map data to rows
    const rows = transactions.map(t => [
      escapeCsv(t.date),
      escapeCsv(t.description),
      escapeCsv(t.category),
      escapeCsv(t.type === 'income' ? 'إيراد' : 'مصروف'),
      escapeCsv(t.amount),
      escapeCsv(t.notes || '')
    ]);

    // Combine headers and rows
    const csvContent = [
      headers.join(','),
      ...rows.map(r => r.join(','))
    ].join('\n');

    // Create Blob with BOM for Arabic support in Excel
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    // Create download link
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `financial_report_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">الإدارة المالية</h2>
          <p className="text-slate-500 mt-1">تتبع الإيرادات والمصروفات وصافي الربح</p>
        </div>
        <div className="flex gap-2">
            <button 
              onClick={handleExportExcel}
              className="bg-white border border-slate-300 text-slate-700 px-4 py-2 rounded-lg text-sm font-medium hover:bg-slate-50 flex items-center transition-colors"
            >
                <FileSpreadsheet size={16} className="ml-2"/>
                تصدير Excel
            </button>
            <button className="bg-emerald-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-emerald-700 flex items-center shadow-sm shadow-emerald-600/20">
                <TrendingUp size={16} className="ml-2"/>
                إضافة إيراد
            </button>
            <button className="bg-rose-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-rose-700 flex items-center shadow-sm shadow-rose-600/20">
                <TrendingDown size={16} className="ml-2"/>
                إضافة مصروف
            </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
            <h3 className="font-bold text-slate-700">سجل المعاملات الأخيرة</h3>
            <button className="text-blue-600 text-sm font-medium hover:underline">عرض التقرير الكامل</button>
        </div>
        <table className="w-full text-right">
            <thead className="bg-white text-slate-500 font-medium text-sm">
                <tr>
                    <th className="p-4 border-b">المعاملة</th>
                    <th className="p-4 border-b">التصنيف</th>
                    <th className="p-4 border-b">التاريخ</th>
                    <th className="p-4 border-b">المبلغ</th>
                </tr>
            </thead>
            <tbody>
                {transactions.map(t => (
                    <tr key={t.id} className="hover:bg-slate-50">
                        <td className="p-4 border-b border-slate-50">
                            <div className="font-medium text-slate-800">{t.description}</div>
                            {t.studentId && <div className="text-xs text-slate-400">مرتبط بطالب</div>}
                            {t.notes && <div className="text-xs text-slate-500 mt-1 italic">{t.notes}</div>}
                        </td>
                         <td className="p-4 border-b border-slate-50">
                            <span className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-xs">
                                {t.category}
                            </span>
                        </td>
                         <td className="p-4 border-b border-slate-50 text-slate-500 text-sm flex items-center">
                            <Calendar size={14} className="ml-1"/>
                            {t.date}
                        </td>
                         <td className={`p-4 border-b border-slate-50 font-bold ${t.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                            {t.type === 'income' ? '+' : '-'} {t.amount} {CURRENCY}
                        </td>
                    </tr>
                ))}
