import React, { useState, useEffect } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import { Users, DollarSign, Wallet, BookOpen, AlertTriangle, Clock, X } from 'lucide-react';
import { StatCard } from '../components/StatCard';
import { Student, Transaction } from '../types';
import { CURRENCY } from '../constants';

interface DashboardProps {
  students: Student[];
  transactions: Transaction[];
}

const data = [
  { name: 'السبت', income: 4000, expenses: 2400 },
  { name: 'الأحد', income: 3000, expenses: 1398 },
  { name: 'الاثنين', income: 2000, expenses: 9800 },
  { name: 'الثلاثاء', income: 2780, expenses: 3908 },
  { name: 'الأربعاء', income: 1890, expenses: 4800 },
  { name: 'الخميس', income: 2390, expenses: 3800 },
  { name: 'الجمعة', income: 3490, expenses: 4300 },
];

export const Dashboard: React.FC<DashboardProps> = ({ students, transactions }) => {
  const [showToast, setShowToast] = useState(true);

  const totalIncome = transactions
    .filter(t => t.type === 'income')
    .reduce((acc, curr) => acc + curr.amount, 0);

  const totalExpense = transactions
    .filter(t => t.type === 'expense')
    .reduce((acc, curr) => acc + curr.amount, 0);

  // Logic for Subscription Expiry
  const today = new Date();
  const warningThresholdDays = 5;

  const subscriptionAlerts = students.reduce((acc, student) => {
      if (!student.subscriptionExpiryDate) return acc;

      const expiryDate = new Date(student.subscriptionExpiryDate);
      const timeDiff = expiryDate.getTime() - today.getTime();
      const daysDiff = Math.ceil(timeDiff / (1000 * 3600 * 24));

      if (daysDiff < 0) {
          acc.push({ type: 'expired', student, days: Math.abs(daysDiff) });
      } else if (daysDiff <= warningThresholdDays) {
          acc.push({ type: 'expiring', student, days: daysDiff });
      }
      return acc;
  }, [] as { type: 'expired' | 'expiring', student: Student, days: number }[]);

  const expiredCount = subscriptionAlerts.filter(a => a.type === 'expired').length;
  const expiringCount = subscriptionAlerts.filter(a => a.type === 'expiring').length;

  return (
    <div className="space-y-6 relative">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="إجمالي الطلاب" 
          value={students.length} 
          icon={Users} 
          color="bg-blue-600"
          trend="12%"
        />
        <StatCard 
          title="الدخل الشهري" 
          value={`${totalIncome.toLocaleString()} ${CURRENCY}`} 
          icon={DollarSign} 
          color="bg-emerald-600"
          trend="8%"
        />
        <StatCard 
          title="المصروفات" 
          value={`${totalExpense.toLocaleString()} ${CURRENCY}`} 
          icon={Wallet} 
          color="bg-rose-600"
        />
        <StatCard 
          title="الحصص النشطة" 
          value={12} 
          icon={BookOpen} 
          color="bg-amber-500"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">الأداء المالي الأسبوعي</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={data}>
                <defs>
                  <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#f43f5e" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b'}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b'}} />
                <Tooltip 
                  contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} 
                />
                <Area type="monotone" dataKey="income" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorIncome)" name="الدخل" />
                <Area type="monotone" dataKey="expenses" stroke="#f43f5e" strokeWidth={3} fillOpacity={1} fill="url(#colorExpense)" name="المصروفات" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center justify-between">
            <span>تنبيهات عاجلة</span>
            {(expiredCount > 0 || expiringCount > 0) && (
              <span className="bg-red-100 text-red-600 text-xs px-2 py-1 rounded-full animate-pulse">
                {expiredCount + expiringCount} تنبيه
              </span>
            )}
          </h3>
          <div className="space-y-4 flex-1 overflow-y-auto max-h-[300px]">

            {/* Subscription Alerts */}
            {subscriptionAlerts.length > 0 ? (
                subscriptionAlerts.map((alert, idx) => (
                    <div key={idx} className={`flex items-start p-3 rounded-xl border ${
                        alert.type === 'expired' 
                        ? 'bg-red-50 border-red-100' 
                        : 'bg-amber-50 border-amber-100'
                    }`}>
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center ml-3 shrink-0 ${
                            alert.type === 'expired' ? 'bg-red-100 text-red-600' : 'bg-amber-100 text-amber-600'
                        }`}>
                            {alert.type === 'expired' ? <AlertTriangle size={16}/> : <Clock size={16}/>}
                        </div>
                        <div>
                            <p className="text-sm font-semibold text-slate-800">
                                {alert.type === 'expired' ? 'اشتراك منتهي' : 'قرب انتهاء الاشتراك'}
                            </p>
                            <p className="text-xs text-slate-600 mt-1">
                                الطالب <span className="font-bold">{alert.student.name}</span>
                                {alert.type === 'expired' 
                                 ? ` انتهى اشتراكه منذ ${alert.days} يوم.` 
                                 : ` ينتهي اشتراكه خلال ${alert.days} يوم.`}
                            </p>
                        </div>
                    </div>
                ))
            ) : (
                <div className="text-center py-4 text-slate-400 text-sm">لا توجد تنبيهات اشتراكات حالياً</div>
            )}

            {/* Existing Alerts */}
            <div className="flex items-start p-3 bg-blue-50 rounded-xl border border-blue-100">
              <div className="w-2 h-2 mt-2 rounded-full bg-blue-500 ml-3 shrink-0"></div>
              <div>
                <p className="text-sm font-semibold text-slate-800">حصة قادمة</p>
                <p className="text-xs text-slate-500 mt-1">مجموعة اللغة الإنجليزية (أ) تبدأ خلال 30 دقيقة.</p>
              </div>
            </div>
             <div className="flex items-start p-3 bg-purple-50 rounded-xl border border-purple-100">
              <div className="w-2 h-2 mt-2 rounded-full bg-purple-500 ml-3 shrink-0"></div>
              <div>
                <p className="text-sm font-semibold text-slate-800">نسخ احتياطي</p>
                <p className="text-xs text-slate-500 mt-1">تم إجراء النسخ الاحتياطي التلقائي بنجاح.</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Toast Notification for Critical Alerts */}
      {showToast && (expiredCount > 0 || expiringCount > 0) && (
        <div className="fixed bottom-8 right-8 left-8 md:left-auto md:w-96 bg-white rounded-xl shadow-2xl border border-slate-200 p-4 animate-in slide-in-from-bottom-5 duration-500 z-50 flex gap-4">
            <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-red-600 shrink-0">
                <AlertTriangle size={24} />
            </div>
            <div className="flex-1">
                <h4 className="font-bold text-slate-800">تنبيهات الاشتراكات</h4>
                <p className="text-sm text-slate-500 mt-1">
                    يوجد {expiredCount} اشتراك منتهي و {expiringCount} اشتراك يوشك على الانتهاء. يرجى مراجعة الطلاب.
                </p>
            </div>
            <button 
                onClick={() => setShowToast(false)}
                className="text-slate-400 hover:text-slate-600 h-fit"
            >
                <X size={20} />
            </button>
        </div>
      )}
    </div>
  );
};

import initSqlJs from 'sql.js';
import { 
  MOCK_STUDENTS, 
  MOCK_TEACHERS, 
  MOCK_GROUPS, 
  MOCK_SESSIONS, 
  MOCK_ATTENDANCE, 
  MOCK_TRANSACTIONS 
} from '../constants';
import { Student, Teacher, Group, Session, AttendanceRecord, Transaction } from '../types';

class DatabaseService {
  db: any = null;
  private STORAGE_KEY = 'educenter_sqlite_db';

  async init() {
    if (this.db) return;

    try {
      const SQL = await initSqlJs({
        locateFile: file => `https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.11.0/${file}`
      });

      // Load from local storage if exists
      const savedDb = localStorage.getItem(this.STORAGE_KEY);

      if (savedDb) {
        const binaryArray = this.base64ToUint8Array(savedDb);
        this.db = new SQL.Database(binaryArray);
        console.log("Database loaded from LocalStorage");
      } else {
        this.db = new SQL.Database();
        this.createTables();
        this.seedData();
        this.save();
        console.log("New Database created and seeded");
      }
    } catch (error) {
      console.error("Failed to initialize database:", error);
    }
  }

  private createTables() {
    const sql = `
      CREATE TABLE IF NOT EXISTS students (
        id TEXT PRIMARY KEY,
        name TEXT,
        phone TEXT,
        parentPhone TEXT,
        grade TEXT,
        balance REAL,
        joinedAt TEXT,
        subscriptionExpiryDate TEXT
      );

      CREATE TABLE IF NOT EXISTS teachers (
        id TEXT PRIMARY KEY,
        name TEXT,
        subject TEXT,
        percentage REAL,
        phone TEXT
      );

      CREATE TABLE IF NOT EXISTS groups (
        id TEXT PRIMARY KEY,
        name TEXT,
        subject TEXT,
        teacherId TEXT,
        schedule TEXT,
        studentIds TEXT -- JSON string
      );

      CREATE TABLE IF NOT EXISTS sessions (
        id TEXT PRIMARY KEY,
        groupId TEXT,
        date TEXT,
        startTime TEXT,
        status TEXT,
        topic TEXT
      );

      CREATE TABLE IF NOT EXISTS attendance (
        id TEXT PRIMARY KEY,
        sessionId TEXT,
        studentId TEXT,
        status TEXT,
        timestamp TEXT
      );

      CREATE TABLE IF NOT EXISTS transactions (
        id TEXT PRIMARY KEY,
        type TEXT,
        amount REAL,
        category TEXT,
        date TEXT,
        description TEXT,
        studentId TEXT,
        notes TEXT
      );
    `;
    this.db.exec(sql);
  }

  private seedData() {
    // Seed Students
    MOCK_STUDENTS.forEach(s => this.addStudent(s, false));
    // Seed Teachers
    MOCK_TEACHERS.forEach(t => this.addTeacher(t, false));
    // Seed Groups
    MOCK_GROUPS.forEach(g => this.addGroup(g, false));
    // Seed Sessions
    MOCK_SESSIONS.forEach(s => this.addSession(s, false));
    // Seed Attendance
    MOCK_ATTENDANCE.forEach(a => this.addAttendance(a, false));
    // Seed Transactions
    MOCK_TRANSACTIONS.forEach(t => this.addTransaction(t, false));
  }

  private save() {
    if (!this.db) return;
    const data = this.db.export();
    const base64 = this.uint8ArrayToBase64(data);
    localStorage.setItem(this.STORAGE_KEY, base64);
  }

  // --- CRUD Operations ---

  // Students
  getAllStudents(): Student[] {
    if (!this.db) return [];
    const res = this.db.exec("SELECT * FROM students");
    if (!res.length) return [];

    return res[0].values.map((row: any) => ({
      id: row[0],
      name: row[1],
      phone: row[2],
      parentPhone: row[3],
      grade: row[4],
      balance: row[5],
      joinedAt: row[6],
      subscriptionExpiryDate: row[7]
    }));
  }

  addStudent(student: Student, autoSave = true) {
    const stmt = this.db.prepare("INSERT OR REPLACE INTO students VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
    stmt.run([
      student.id, 
      student.name, 
      student.phone, 
      student.parentPhone, 
      student.grade, 
      student.balance, 
      student.joinedAt,
      student.subscriptionExpiryDate
    ]);
    stmt.free();
    if (autoSave) this.save();
  }

  deleteStudent(id: string) {
      this.db.run("DELETE FROM students WHERE id = ?", [id]);
      this.save();
  }

  updateStudentBalance(id: string, newBalance: number) {
      this.db.run("UPDATE students SET balance = ? WHERE id = ?", [newBalance, id]);
      this.save();
  }

  // Teachers
  getAllTeachers(): Teacher[] {
    if (!this.db) return [];
    const res = this.db.exec("SELECT * FROM teachers");
    if (!res.length) return [];
    return res[0].values.map((row: any) => ({
      id: row[0], name: row[1], subject: row[2], percentage: row[3], phone: row[4]
    }));
  }

  addTeacher(teacher: Teacher, autoSave = true) {
    this.db.run("INSERT OR REPLACE INTO teachers VALUES (?, ?, ?, ?, ?)", [
        teacher.id, teacher.name, teacher.subject, teacher.percentage, teacher.phone
    ]);
    if (autoSave) this.save();
  }

  // Groups
  getAllGroups(): Group[] {
      if (!this.db) return [];
      const res = this.db.exec("SELECT * FROM groups");
      if (!res.length) return [];
      return res[0].values.map((row: any) => ({
          id: row[0],
          name: row[1],
          subject: row[2],
          teacherId: row[3],
          schedule: row[4],
          studentIds: JSON.parse(row[5])
      }));
  }

  addGroup(group: Group, autoSave = true) {
      this.db.run("INSERT OR REPLACE INTO groups VALUES (?, ?, ?, ?, ?, ?)", [
          group.id, group.name, group.subject, group.teacherId, group.schedule, JSON.stringify(group.studentIds)
      ]);
      if (autoSave) this.save();
  }

  // Sessions
  getAllSessions(): Session[] {
      if (!this.db) return [];
      const res = this.db.exec("SELECT * FROM sessions");
      if (!res.length) return [];
      return res[0].values.map((row: any) => ({
          id: row[0], groupId: row[1], date: row[2], startTime: row[3], status: row[4], topic: row[5]
      }));
  }

  addSession(session: Session, autoSave = true) {
      this.db.run("INSERT OR REPLACE INTO sessions VALUES (?, ?, ?, ?, ?, ?)", [
          session.id, session.groupId, session.date, session.startTime, session.status, session.topic
      ]);
      if (autoSave) this.save();
  }

  // Attendance
  getAllAttendance(): AttendanceRecord[] {
      if (!this.db) return [];
      const res = this.db.exec("SELECT * FROM attendance");
      if (!res.length) return [];
      return res[0].values.map((row: any) => ({
          id: row[0], sessionId: row[1], studentId: row[2], status: row[3], timestamp: row[4]
      }));
  }

  addAttendance(record: AttendanceRecord, autoSave = true) {
      // Remove existing for same session/student to avoid duplicates (logic from App.tsx)
      this.db.run("DELETE FROM attendance WHERE sessionId = ? AND studentId = ?", [record.sessionId, record.studentId]);

      this.db.run("INSERT INTO attendance VALUES (?, ?, ?, ?, ?)", [
          record.id, record.sessionId, record.studentId, record.status, record.timestamp
      ]);
      if (autoSave) this.save();
  }

  // Transactions
  getAllTransactions(): Transaction[] {
      if (!this.db) return [];
      const res = this.db.exec("SELECT * FROM transactions");
      if (!res.length) return [];
      return res[0].values.map((row: any) => ({
          id: row[0], type: row[1], amount: row[2], category: row[3], date: row[4], description: row[5], studentId: row[6], notes: row[7]
      }));
  }

  addTransaction(t: Transaction, autoSave = true) {
      this.db.run("INSERT OR REPLACE INTO transactions VALUES (?, ?, ?, ?, ?, ?, ?, ?)", [
          t.id, t.type, t.amount, t.category, t.date, t.description, t.studentId, t.notes
      ]);
      if (autoSave) this.save();
  }

  // --- Helpers for Binary Storage ---
  private uint8ArrayToBase64(u8Arr: Uint8Array): string {
    let chunk = 0x8000;
    let index = 0;
    let length = u8Arr.length;
    let result = '';
    while (index < length) {
        let slice = u8Arr.subarray(index, Math.min(index + chunk, length));
        result += String.fromCharCode.apply(null, slice as unknown as number[]);
        index += chunk;
    }
    return btoa(result);
  }

  private base64ToUint8Array(base64: string): Uint8Array {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }
}

