import initSqlJs from 'sql.js';
import { 
  MOCK_STUDENTS, 
  MOCK_TEACHERS, 
  MOCK_GROUPS, 
  MOCK_SESSIONS, 
  MOCK_ATTENDANCE, 
  MOCK_TRANSACTIONS 
} from '../constants';
import { Student, Teacher, Group, Session, AttendanceRecord, Transaction } from '../types';

class DatabaseService {
  db: any = null;
  private STORAGE_KEY = 'educenter_sqlite_db';

  async init() {
    if (this.db) return;

    try {
      // Fetch the WASM binary manually to avoid "fs.readFileSync is not implemented" errors
      // which occur when sql.js tries to detect the environment or load the file automatically.
      const wasmUrl = 'https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.11.0/sql-wasm.wasm';
      const response = await fetch(wasmUrl);

      if (!response.ok) {
        throw new Error(`Failed to load WASM: ${response.statusText}`);
      }

      const wasmBinary = await response.arrayBuffer();

      const SQL = await initSqlJs({
        wasmBinary
      });

      // Load from local storage if exists
      const savedDb = localStorage.getItem(this.STORAGE_KEY);

      if (savedDb) {
        const binaryArray = this.base64ToUint8Array(savedDb);
        this.db = new SQL.Database(binaryArray);
        console.log("Database loaded from LocalStorage");
      } else {
        this.db = new SQL.Database();
        this.createTables();
        this.seedData();
        this.save();
        console.log("New Database created and seeded");
      }
    } catch (error) {
      console.error("Failed to initialize database:", error);
    }
  }

  private createTables() {
    const sql = `
      CREATE TABLE IF NOT EXISTS students (
        id TEXT PRIMARY KEY,
        name TEXT,
        phone TEXT,
        parentPhone TEXT,
        grade TEXT,
        balance REAL,
        joinedAt TEXT,
        subscriptionExpiryDate TEXT
      );

      CREATE TABLE IF NOT EXISTS teachers (
        id TEXT PRIMARY KEY,
        name TEXT,
        subject TEXT,
        percentage REAL,
        phone TEXT
      );

      CREATE TABLE IF NOT EXISTS groups (
        id TEXT PRIMARY KEY,
        name TEXT,
        subject TEXT,
        teacherId TEXT,
        schedule TEXT,
        studentIds TEXT -- JSON string
      );

      CREATE TABLE IF NOT EXISTS sessions (
        id TEXT PRIMARY KEY,
        groupId TEXT,
        date TEXT,
        startTime TEXT,
        status TEXT,
        topic TEXT
      );

      CREATE TABLE IF NOT EXISTS attendance (
        id TEXT PRIMARY KEY,
        sessionId TEXT,
        studentId TEXT,
        status TEXT,
        timestamp TEXT
      );

      CREATE TABLE IF NOT EXISTS transactions (
        id TEXT PRIMARY KEY,
        type TEXT,
        amount REAL,
        category TEXT,
        date TEXT,
        description TEXT,
        studentId TEXT,
        notes TEXT
      );
    `;
    this.db.exec(sql);
  }

  private seedData() {
    // Seed Students
    MOCK_STUDENTS.forEach(s => this.addStudent(s, false));
    // Seed Teachers
    MOCK_TEACHERS.forEach(t => this.addTeacher(t, false));
    // Seed Groups
    MOCK_GROUPS.forEach(g => this.addGroup(g, false));
    // Seed Sessions
    MOCK_SESSIONS.forEach(s => this.addSession(s, false));
    // Seed Attendance
    MOCK_ATTENDANCE.forEach(a => this.addAttendance(a, false));
    // Seed Transactions
    MOCK_TRANSACTIONS.forEach(t => this.addTransaction(t, false));
  }

  private save() {
    if (!this.db) return;
    const data = this.db.export();
    const base64 = this.uint8ArrayToBase64(data);
    localStorage.setItem(this.STORAGE_KEY, base64);
  }

  // --- CRUD Operations ---

  // Students
  getAllStudents(): Student[] {
    if (!this.db) return [];
    const res = this.db.exec("SELECT * FROM students");
    if (!res.length) return [];

    return res[0].values.map((row: any) => ({
      id: row[0],
      name: row[1],
      phone: row[2],
      parentPhone: row[3],
      grade: row[4],
      balance: row[5],
      joinedAt: row[6],
      subscriptionExpiryDate: row[7]
    }));
  }

  addStudent(student: Student, autoSave = true) {
    const stmt = this.db.prepare("INSERT OR REPLACE INTO students VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
    stmt.run([
      student.id, 
      student.name, 
      student.phone, 
      student.parentPhone, 
      student.grade, 
      student.balance, 
      student.joinedAt,
      student.subscriptionExpiryDate
    ]);
    stmt.free();
    if (autoSave) this.save();
  }

  deleteStudent(id: string) {
      this.db.run("DELETE FROM students WHERE id = ?", [id]);
      this.save();
  }

  updateStudentBalance(id: string, newBalance: number) {
      this.db.run("UPDATE students SET balance = ? WHERE id = ?", [newBalance, id]);
      this.save();
  }

  // Teachers
  getAllTeachers(): Teacher[] {
    if (!this.db) return [];
    const res = this.db.exec("SELECT * FROM teachers");
