                            <p className="font-bold text-slate-700">{stats.sessionsCount}</p>
                        </div>
                        <div className="text-center">
                            <p className="text-xs text-slate-400 mb-1">الطلاب</p>
                            <p className="font-bold text-slate-700">{stats.studentsCount}</p>
