const App: React.FC = () => {
  const [activeView, setActiveView] = useState('dashboard');
  const [isDbReady, setIsDbReady] = useState(false);

  // State populated from DB
  const [students, setStudents] = useState<Student[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [sessions, setSessions] = useState<Session[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [teachers, setTeachers] = useState<Teacher[]>([]);

  // Initialize DB on mount
  useEffect(() => {
    const initData = async () => {
        await db.init();
        refreshData();
        setIsDbReady(true);
    };
    initData();
  }, []);

  const refreshData = () => {
      setStudents(db.getAllStudents());
      setTransactions(db.getAllTransactions());
      setGroups(db.getAllGroups());
      setSessions(db.getAllSessions());
      setAttendance(db.getAllAttendance());
      setTeachers(db.getAllTeachers());
  };

  const handleAddStudent = (newStudent: Student) => {
    db.addStudent(newStudent);
    refreshData();
  };

  const handleDeleteStudent = (id: string) => {
    db.deleteStudent(id);
    refreshData();
  };

  const handleAddSession = (newSession: Session) => {
    db.addSession(newSession);
    refreshData();
  };

  const handleUpdateSession = (updatedSession: Session) => {
    db.addSession(updatedSession); // addSession uses REPLACE
    refreshData();
  };

  const handleUpdateAttendance = (record: AttendanceRecord) => {
    db.addAttendance(record);
    refreshData();
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    db.addTransaction(newTransaction);

    // Update Student Balance logic via DB
    if (newTransaction.studentId) {
        const student = students.find(s => s.id === newTransaction.studentId);
        if (student) {
            const change = newTransaction.type === 'income' ? newTransaction.amount : -newTransaction.amount;
            const newBalance = student.balance + change;
            db.updateStudentBalance(student.id, newBalance);
        }
    }
    refreshData();
  };

  const handleAddTeacher = (teacher: Teacher) => {
    db.addTeacher(teacher);
    refreshData();
  };

  const handleDeleteTeacher = (id: string) => {
    db.deleteTeacher(id);
    refreshData();
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard students={students} transactions={transactions} />;
      case 'students':
        return (
            <Students 
                students={students} 
                transactions={transactions}
                onAddStudent={handleAddStudent} 
                onDeleteStudent={handleDeleteStudent}
                onAddTransaction={handleAddTransaction}
            />
        );
      case 'teachers':
        return (
          <Teachers 
            teachers={teachers} 
            groups={groups}
            sessions={sessions}
            onAddTeacher={handleAddTeacher}
            onDeleteTeacher={handleDeleteTeacher}
          />
        );
      case 'groups':
        return (
          <Groups 
            groups={groups} 
            students={students} 
            sessions={sessions} 
            attendance={attendance}
            onAddSession={handleAddSession}
            onUpdateSession={handleUpdateSession}
            onUpdateAttendance={handleUpdateAttendance}
          />
        );
      case 'financials':
        return <Financials transactions={transactions} />;
      case 'settings':
        return <ArchitectureInfo />;
      default:
        return <Dashboard students={students} transactions={transactions} />;
    }
  };

  if (!isDbReady) {
      return (
          <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 text-slate-600 gap-4">
              <Loader2 className="animate-spin text-blue-600" size={48} />
              <p className="font-medium">جاري تحميل قاعدة البيانات...</p>
          </div>
      );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      {/* Main Content Area */}
      <main className="flex-1 mr-64 h-screen overflow-y-auto p-8 relative">
        <header className="flex justify-between items-center mb-8">
          <div>
             {/* Breadcrumbs or Title could go here */}
          </div>
          <div className="flex items-center gap-4">
             <div className="text-left hidden md:block">
                <p className="text-sm font-bold text-slate-700">أحمد المدير</p>
                <p className="text-xs text-slate-500">آخر ظهور: منذ دقيقتين</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
                <img src="https://picsum.photos/100/100" alt="Admin" />
             </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
           {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Group, Session, Student, AttendanceRecord } from '../types';
import { GroupList } from '../components/groups/GroupList';
import { GroupDetails } from '../components/groups/GroupDetails';
import { AttendanceSheet } from '../components/groups/AttendanceSheet';

interface GroupsProps {
  groups: Group[];
  students: Student[];
  sessions: Session[];
  attendance: AttendanceRecord[];
  onAddSession: (session: Session) => void;
  onUpdateSession: (session: Session) => void;
  onUpdateAttendance: (record: AttendanceRecord) => void;
}

export const Groups: React.FC<GroupsProps> = ({ 
  groups, 
  students, 
  sessions, 
  attendance,
  onAddSession,
  onUpdateSession,
  onUpdateAttendance
}) => {
  // Navigation State (Router Logic)
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);

  // --- Handlers ---
  const handleGroupSelect = (id: string) => {
    setSelectedGroupId(id);
    setSelectedSessionId(null); // Reset session when changing group
  };

  const handleSessionSelect = (id: string) => {
    setSelectedSessionId(id);
  };

  const handleBackToGroups = () => {
    setSelectedGroupId(null);
    setSelectedSessionId(null);
  };

  const handleBackToGroupDetails = () => {
    setSelectedSessionId(null);
  };

  // --- Render Logic (View Routing) ---

  // 1. Attendance View (Deepest Level)
  if (selectedSessionId && selectedGroupId) {
    const session = sessions.find(s => s.id === selectedSessionId);
    const group = groups.find(g => g.id === selectedGroupId);

    if (session && group) {
      return (
        <AttendanceSheet 
          group={group}
          session={session}
          students={students}
          attendance={attendance}
          onBack={handleBackToGroupDetails}
          onUpdateAttendance={onUpdateAttendance}
          onUpdateSession={onUpdateSession}
        />
      );
    }
  }

  // 2. Group Details View (Middle Level)
  if (selectedGroupId) {
    const group = groups.find(g => g.id === selectedGroupId);
    const groupSessions = sessions.filter(s => s.groupId === selectedGroupId);

    if (group) {
      return (
        <GroupDetails 
          group={group}
          sessions={groupSessions}
          onBack={handleBackToGroups}
          onSessionClick={handleSessionSelect}
          onAddSession={onAddSession}
          onUpdateSession={onUpdateSession}
        />
      );
    }
  }

  // 3. Group List View (Root Level)
  return (
    <GroupList 
      groups={groups} 
      onGroupClick={handleGroupSelect} 
    />
  );
};

import React, { useState } from 'react';
import { ArrowRight, Play, Calendar as CalendarIcon, List } from 'lucide-react';
import { Group, Session } from '../../types';
import { SessionList } from './SessionList';
import { SessionCalendar } from './SessionCalendar';
import { SessionModal } from './SessionModal';

interface GroupDetailsProps {
  group: Group;
  sessions: Session[];
  onBack: () => void;
  onSessionClick: (id: string) => void;
  onAddSession: (session: Session) => void;
  onUpdateSession: (session: Session) => void;
}

export const GroupDetails: React.FC<GroupDetailsProps> = ({
  group,
  sessions,
  onBack,
  onSessionClick,
  onAddSession,
  onUpdateSession
}) => {
  // UI State (Localized)
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('list');
  const [activeTab, setActiveTab] = useState<'upcoming' | 'history'>('upcoming');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSession, setEditingSession] = useState<Session | null>(null);
  const [initialDate, setInitialDate] = useState<string | undefined>(undefined);

  // Derived Data
  const upcomingSessions = sessions
    .filter(s => s.status !== 'completed')
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  const historySessions = sessions
    .filter(s => s.status === 'completed')
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Handlers
  const handleQuickStart = () => {
    const newSession: Session = {
      id: Date.now().toString(),
      groupId: group.id,
      date: new Date().toISOString().split('T')[0],
      startTime: new Date().toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit" }),
      status: 'active',
      topic: 'حصة جديدة - ' + new Date().toLocaleDateString('ar-EG')
    };
    onAddSession(newSession);
    onSessionClick(newSession.id);
  };

  const handleOpenAddModal = (date?: string) => {
    setEditingSession(null);
    setInitialDate(date);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (session: Session) => {
    setEditingSession(session);
    setInitialDate(undefined);
    setIsModalOpen(true);
  };

  const handleModalSubmit = (data: { topic: string; date: string; startTime: string }) => {
    if (editingSession) {
      onUpdateSession({
        ...editingSession,
        ...data
      });
    } else {
      onAddSession({
        id: Date.now().toString(),
        groupId: group.id,
        status: 'scheduled',
        ...data
      });
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors">
          <ArrowRight size={24} />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{group.name}</h2>
          <p className="text-slate-500 mt-1">إدارة الحصص والجداول</p>
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex flex-col md:flex-row gap-4">
        <button 
            onClick={handleQuickStart}
            className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white p-4 rounded-xl font-bold flex items-center justify-center shadow-lg shadow-emerald-600/20 transition-all"
        >
            <Play size={20} className="ml-2 fill-current" />
            بدء حصة فورية
        </button>
        <button 
            onClick={() => handleOpenAddModal()}
            className="flex-1 bg-white border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50 text-slate-600 p-4 rounded-xl font-medium flex items-center justify-center transition-all"
        >
            <CalendarIcon size={20} className="ml-2" />
            جدولة حصة جديدة
        </button>
      </div>

      {/* View Toggle & Tabs */}
      <div className="flex flex-col sm:flex-row justify-between items-center border-b border-slate-200 mt-6 gap-4">
        <div className="flex gap-6 w-full sm:w-auto">
            <button 
                onClick={() => setActiveTab('upcoming')}
                className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'upcoming' && viewMode === 'list' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
                disabled={viewMode === 'calendar'}
            >
                الحصص القادمة
                {activeTab === 'upcoming' && viewMode === 'list' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
            <button 
                 onClick={() => setActiveTab('history')}
                 className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'history' && viewMode === 'list' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
                disabled={viewMode === 'calendar'}
            >
                سجل الحصص السابقة
                {activeTab === 'history' && viewMode === 'list' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-lg mb-2 sm:mb-0">
            <button 
                onClick={() => setViewMode('list')}
                className={`p-2 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${
                    viewMode === 'list' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                <List size={16} />
                قائمة
            </button>
            <button 
                onClick={() => setViewMode('calendar')}
                className={`p-2 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${
                    viewMode === 'calendar' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                <CalendarIcon size={16} />
                تقويم
            </button>
        </div>
      </div>

      {/* Content */}
      {viewMode === 'calendar' ? (
        <SessionCalendar 
          sessions={sessions}
          onSessionClick={onSessionClick}
          onAddSession={handleOpenAddModal}
        />
      ) : (
        <SessionList 
          sessions={activeTab === 'upcoming' ? upcomingSessions : historySessions}
          onSessionClick={onSessionClick}
          onEditSession={handleOpenEditModal}
        />
      )}

      {/* Modal */}
      <SessionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleModalSubmit}
        initialData={editingSession ? editingSession : { date: initialDate }}
        title={editingSession ? 'تعديل موعد الحصة' : 'جدولة حصة جديدة'}
        submitLabel={editingSession ? 'حفظ التعديلات' : 'حفظ الحصة'}
      />
    </div>
  );
};

