          <ul className="list-disc list-inside text-sm text-slate-600 space-y-1">
            <li>SQLite (sql.js) يعمل داخل المتصفح.</li>
            <li>تخزين الملف الثنائي للبيانات في LocalStorage.</li>
            <li>استرجاع وعرض البيانات فوراً بدون إنترنت.</li>
          </ul>
        </div>
      </div>
    </div>
  </div>
);

const App: React.FC = () => {
  const [activeView, setActiveView] = useState('dashboard');
  const [isDbReady, setIsDbReady] = useState(false);

  // State populated from DB
  const [students, setStudents] = useState<Student[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [sessions, setSessions] = useState<Session[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [teachers, setTeachers] = useState<Teacher[]>([]);

  // Initialize DB on mount
  useEffect(() => {
    const initData = async () => {
        await db.init();
        refreshData();
        setIsDbReady(true);
    };
    initData();
  }, []);

  const refreshData = () => {
      setStudents(db.getAllStudents());
      setTransactions(db.getAllTransactions());
      setGroups(db.getAllGroups());
      setSessions(db.getAllSessions());
      setAttendance(db.getAllAttendance());
      setTeachers(db.getAllTeachers());
  };

  const handleAddStudent = (newStudent: Student) => {
    db.addStudent(newStudent);
    refreshData();
  };

  const handleDeleteStudent = (id: string) => {
    db.deleteStudent(id);
    refreshData();
  };

  const handleAddSession = (newSession: Session) => {
    db.addSession(newSession);
    refreshData();
  };

  const handleUpdateSession = (updatedSession: Session) => {
    db.addSession(updatedSession); // addSession uses REPLACE
    refreshData();
  };

  const handleUpdateAttendance = (record: AttendanceRecord) => {
    db.addAttendance(record);
    refreshData();
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    db.addTransaction(newTransaction);

    // Update Student Balance logic via DB
    if (newTransaction.studentId) {
        // Fetch fresh data from DB to ensure balance is accurate
        const currentStudents = db.getAllStudents();
        const student = currentStudents.find(s => s.id === newTransaction.studentId);

        if (student) {
            const change = newTransaction.type === 'income' ? newTransaction.amount : -newTransaction.amount;
            const newBalance = student.balance + change;
            db.updateStudentBalance(student.id, newBalance);
        }
    }
    refreshData();
  };

  const handleAddTeacher = (teacher: Teacher) => {
    db.addTeacher(teacher);
    refreshData();
  };

  const handleDeleteTeacher = (id: string) => {
    db.deleteTeacher(id);
    refreshData();
  };

  const handleAddGroup = (group: Group) => {
    db.addGroup(group);
    refreshData();
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard students={students} transactions={transactions} />;
      case 'students':
        return (
            <Students 
                students={students} 
                transactions={transactions}
                onAddStudent={handleAddStudent} 
                onDeleteStudent={handleDeleteStudent}
                onAddTransaction={handleAddTransaction}
            />
        );
      case 'teachers':
        return (
          <Teachers 
            teachers={teachers} 
            groups={groups}
            sessions={sessions}
            onAddTeacher={handleAddTeacher}
            onDeleteTeacher={handleDeleteTeacher}
          />
        );
      case 'groups':
        return (
          <Groups 
            groups={groups} 
            students={students} 
            sessions={sessions} 
            attendance={attendance}
            teachers={teachers}
            onAddSession={handleAddSession}
            onUpdateSession={handleUpdateSession}
            onUpdateAttendance={handleUpdateAttendance}
            onAddGroup={handleAddGroup}
          />
        );
      case 'financials':
        return (
          <Financials 
            transactions={transactions} 
            onAddTransaction={handleAddTransaction}
          />
        );
      case 'reports':
        return (
          <Reports 
             students={students}
             teachers={teachers}
             transactions={transactions}
             attendance={attendance}
             groups={groups}
             sessions={sessions}
          />
        );
      case 'settings':
        return <ArchitectureInfo />;
      default:
        return <Dashboard students={students} transactions={transactions} />;
    }
  };

  if (!isDbReady) {
      return (
          <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 text-slate-600 gap-4">
              <Loader2 className="animate-spin text-blue-600" size={48} />
              <p className="font-medium">جاري تحميل قاعدة البيانات...</p>
          </div>
      );
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar activeView={activeView} setActiveView={setActiveView} />

      {/* Main Content Area */}
      <main className="flex-1 mr-64 h-screen overflow-y-auto p-8 relative">
        <header className="flex justify-between items-center mb-8 print:hidden">
          <div>
             {/* Breadcrumbs or Title could go here */}
          </div>
          <div className="flex items-center gap-4">
             <div className="text-left hidden md:block">
                <p className="text-sm font-bold text-slate-700">أحمد المدير</p>
                <p className="text-xs text-slate-500">آخر ظهور: منذ دقيقتين</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
                <img src="https://picsum.photos/100/100" alt="Admin" />
             </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
           {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Search, X, Check } from 'lucide-react';
import { Student } from '../../types';

interface StudentSelectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  allStudents: Student[];
  selectedIds: string[];
  onSave: (ids: string[]) => void;
}

export const StudentSelectionModal: React.FC<StudentSelectionModalProps> = ({
  isOpen,
  onClose,
  allStudents,
  selectedIds,
  onSave
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [currentSelected, setCurrentSelected] = useState<Set<string>>(new Set(selectedIds));

  // Reset state when modal opens
  useEffect(() => {
    if (isOpen) {
      setCurrentSelected(new Set(selectedIds));
      setSearchTerm('');
    }
  }, [isOpen, selectedIds]);

  if (!isOpen) return null;

  const toggleSelection = (id: string) => {
    const newSelected = new Set(currentSelected);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setCurrentSelected(newSelected);
  };

  const filteredStudents = allStudents.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.phone.includes(searchTerm)
  );

  const handleSave = () => {
    onSave(Array.from(currentSelected));
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center shrink-0">
          <div>
            <h3 className="text-xl font-bold text-slate-800">إدارة طلاب المجموعة</h3>
            <p className="text-sm text-slate-500 mt-1">تم تحديد {currentSelected.size} طالب</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <X size={24} />
          </button>
        </div>

        <div className="p-4 border-b border-slate-100 bg-slate-50 shrink-0">
          <div className="relative">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="بحث عن طالب (الاسم أو رقم الهاتف)..." 
              className="w-full pl-4 pr-10 py-2.5 rounded-lg border border-slate-200 focus:outline-none focus:border-blue-500 transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              autoFocus
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2">
           <div className="space-y-1">
             {filteredStudents.map(student => {
               const isSelected = currentSelected.has(student.id);
               return (
                 <div 
                    key={student.id}
                    onClick={() => toggleSelection(student.id)}
                    className={`flex items-center justify-between p-3 rounded-xl cursor-pointer transition-all border ${
                      isSelected ? 'bg-blue-50 border-blue-200' : 'hover:bg-slate-50 border-transparent'
                    }`}
                 >
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm shrink-0 ${
                        isSelected ? 'bg-blue-600 text-white' : 'bg-slate-200 text-slate-600'
                      }`}>
                        {isSelected ? <Check size={20} /> : student.name.charAt(0)}
                      </div>
                      <div>
                        <p className={`font-semibold ${isSelected ? 'text-blue-800' : 'text-slate-800'}`}>{student.name}</p>
                        <p className="text-xs text-slate-500">{student.grade} • {student.phone}</p>
                      </div>
                    </div>
                 </div>
               );
             })}
           </div>
           {filteredStudents.length === 0 && (
             <div className="p-8 text-center text-slate-400">
                {searchTerm ? 'لا توجد نتائج مطابقة للبحث' : 'لا يوجد طلاب'}
             </div>
           )}
        </div>

        <div className="p-4 border-t border-slate-100 flex gap-3 shrink-0">
          <button 
            onClick={handleSave}
            className="flex-1 bg-blue-600 text-white py-2.5 rounded-lg font-medium hover:bg-blue-700 transition-colors"
          >
            حفظ التغييرات
          </button>
          <button 
            onClick={onClose}
            className="flex-1 bg-slate-100 text-slate-600 py-2.5 rounded-lg font-medium hover:bg-slate-200 transition-colors"
          >
            إلغاء
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ArrowRight, Play, Calendar as CalendarIcon, List, Users } from 'lucide-react';
import { Group, Session, Student } from '../../types';
import { SessionList } from './SessionList';
import { SessionCalendar } from './SessionCalendar';
import { SessionModal } from './SessionModal';
import { StudentSelectionModal } from './StudentSelectionModal';

interface GroupDetailsProps {
  group: Group;
  sessions: Session[];
  students: Student[];
  onBack: () => void;
  onSessionClick: (id: string) => void;
  onAddSession: (session: Session) => void;
  onUpdateSession: (session: Session) => void;
  onUpdateGroup: (group: Group) => void;
}

export const GroupDetails: React.FC<GroupDetailsProps> = ({
  group,
  sessions,
  students,
  onBack,
  onSessionClick,
  onAddSession,
  onUpdateSession,
  onUpdateGroup
}) => {
  // UI State (Localized)
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('list');
  const [activeTab, setActiveTab] = useState<'upcoming' | 'history'>('upcoming');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
  const [editingSession, setEditingSession] = useState<Session | null>(null);
  const [initialDate, setInitialDate] = useState<string | undefined>(undefined);

  // Derived Data
  const upcomingSessions = sessions
    .filter(s => s.status !== 'completed')
    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

  const historySessions = sessions
    .filter(s => s.status === 'completed')
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Handlers
  const handleQuickStart = () => {
    const newSession: Session = {
      id: Date.now().toString(),
      groupId: group.id,
      date: new Date().toISOString().split('T')[0],
      startTime: new Date().toLocaleTimeString('en-US', { hour12: false, hour: "2-digit", minute: "2-digit" }),
      status: 'active',
      topic: 'حصة جديدة - ' + new Date().toLocaleDateString('ar-EG')
    };
    onAddSession(newSession);
    onSessionClick(newSession.id);
  };

  const handleOpenAddModal = (date?: string) => {
    setEditingSession(null);
    setInitialDate(date);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (session: Session) => {
    setEditingSession(session);
    setInitialDate(undefined);
    setIsModalOpen(true);
  };

  const handleModalSubmit = (data: { topic: string; date: string; startTime: string }) => {
    if (editingSession) {
      onUpdateSession({
        ...editingSession,
        ...data
      });
    } else {
      onAddSession({
        id: Date.now().toString(),
        groupId: group.id,
        status: 'scheduled',
        ...data
      });
    }
    setIsModalOpen(false);
  };

  const handleUpdateStudents = (selectedIds: string[]) => {
      onUpdateGroup({
          ...group,
          studentIds: selectedIds
      });
      setIsStudentModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors">
          <ArrowRight size={24} />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-slate-800">{group.name}</h2>
          <p className="text-slate-500 mt-1">إدارة الحصص والجداول</p>
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex flex-col md:flex-row gap-4">
        <button 
            onClick={handleQuickStart}
            className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white p-4 rounded-xl font-bold flex items-center justify-center shadow-lg shadow-emerald-600/20 transition-all"
        >
            <Play size={20} className="ml-2 fill-current" />
            بدء حصة فورية
        </button>
        <button 
            onClick={() => handleOpenAddModal()}
            className="flex-1 bg-white border-2 border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50 text-slate-600 p-4 rounded-xl font-medium flex items-center justify-center transition-all"
        >
            <CalendarIcon size={20} className="ml-2" />
            جدولة حصة جديدة
        </button>
        <button 
            onClick={() => setIsStudentModalOpen(true)}
            className="flex-1 bg-white border border-slate-200 hover:border-blue-400 hover:bg-blue-50 text-slate-600 p-4 rounded-xl font-medium flex items-center justify-center transition-all shadow-sm"
        >
            <Users size={20} className="ml-2" />
            إدارة الطلاب ({group.studentIds.length})
        </button>
      </div>

      {/* View Toggle & Tabs */}
      <div className="flex flex-col sm:flex-row justify-between items-center border-b border-slate-200 mt-6 gap-4">
        <div className="flex gap-6 w-full sm:w-auto">
            <button 
                onClick={() => setActiveTab('upcoming')}
                className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'upcoming' && viewMode === 'list' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
                disabled={viewMode === 'calendar'}
            >
                الحصص القادمة
                {activeTab === 'upcoming' && viewMode === 'list' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
            <button 
                 onClick={() => setActiveTab('history')}
                 className={`pb-3 font-medium text-sm transition-colors relative ${
                    activeTab === 'history' && viewMode === 'list' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-700'
                }`}
                disabled={viewMode === 'calendar'}
            >
                سجل الحصص السابقة
                {activeTab === 'history' && viewMode === 'list' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-600 rounded-t-full"></div>}
            </button>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-lg mb-2 sm:mb-0">
            <button 
                onClick={() => setViewMode('list')}
                className={`p-2 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${
                    viewMode === 'list' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                <List size={16} />
                قائمة
            </button>
            <button 
                onClick={() => setViewMode('calendar')}
                className={`p-2 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${
                    viewMode === 'calendar' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
            >
                <CalendarIcon size={16} />
                تقويم
            </button>
        </div>
      </div>

      {/* Content */}
      {viewMode === 'calendar' ? (
        <SessionCalendar 
          sessions={sessions}
          onSessionClick={onSessionClick}
          onAddSession={handleOpenAddModal}
        />
      ) : (
        <SessionList 
          sessions={activeTab === 'upcoming' ? upcomingSessions : historySessions}
          onSessionClick={onSessionClick}
          onEditSession={handleOpenEditModal}
        />
      )}

      {/* Session Modal */}
      <SessionModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleModalSubmit}
        initialData={editingSession ? editingSession : { date: initialDate }}
        title={editingSession ? 'تعديل موعد الحصة' : 'جدولة حصة جديدة'}
        submitLabel={editingSession ? 'حفظ التعديلات' : 'حفظ الحصة'}
      />

      {/* Student Management Modal */}
      <StudentSelectionModal 
          isOpen={isStudentModalOpen} 
          onClose={() => setIsStudentModalOpen(false)}
          allStudents={students}
          selectedIds={group.studentIds}
          onSave={handleUpdateStudents}
      />
    </div>
  );
};

import React, { useState } from 'react';
import { Group, Session, Student, AttendanceRecord, Teacher } from '../types';
import { GroupList } from '../components/groups/GroupList';
import { GroupDetails } from '../components/groups/GroupDetails';
import { AttendanceSheet } from '../components/groups/AttendanceSheet';
import { X } from 'lucide-react';

interface GroupsProps {
  groups: Group[];
  students: Student[];
  sessions: Session[];
  attendance: AttendanceRecord[];
  teachers: Teacher[]; 
  onAddSession: (session: Session) => void;
  onUpdateSession: (session: Session) => void;
  onUpdateAttendance: (record: AttendanceRecord) => void;
  onAddGroup: (group: Group) => void; 
}

export const Groups: React.FC<GroupsProps> = ({ 
  groups, 
  students, 
  sessions, 
  attendance,
  teachers,
  onAddSession,
  onUpdateSession,
  onUpdateAttendance,
  onAddGroup
}) => {
  // Navigation State (Router Logic)
  const [selectedGroupId, setSelectedGroupId] = useState<string | null>(null);
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);

  // Modal State
  const [isAddGroupModalOpen, setIsAddGroupModalOpen] = useState(false);
  const [newGroupForm, setNewGroupForm] = useState({
      name: '',
      subject: '',
      teacherId: '',
      schedule: ''
  });

  // --- Handlers ---
  const handleGroupSelect = (id: string) => {
    setSelectedGroupId(id);
    setSelectedSessionId(null); // Reset session when changing group
  };

  const handleSessionSelect = (id: string) => {
    setSelectedSessionId(id);
  };

  const handleBackToGroups = () => {
    setSelectedGroupId(null);
    setSelectedSessionId(null);
  };

  const handleBackToGroupDetails = () => {
    setSelectedSessionId(null);
  };

  const handleCreateGroup = (e: React.FormEvent) => {
      e.preventDefault();
      const newGroup: Group = {
          id: Date.now().toString(),
          name: newGroupForm.name,
          subject: newGroupForm.subject,
          teacherId: newGroupForm.teacherId,
          schedule: newGroupForm.schedule,
          studentIds: [] // Start with no students, add later
      };
      onAddGroup(newGroup);
      setIsAddGroupModalOpen(false);
      setNewGroupForm({ name: '', subject: '', teacherId: '', schedule: '' });
  };

  // --- Render Logic (View Routing) ---

  // 1. Attendance View (Deepest Level)
  if (selectedSessionId && selectedGroupId) {
    const session = sessions.find(s => s.id === selectedSessionId);
    const group = groups.find(g => g.id === selectedGroupId);

    if (session && group) {
      return (
        <AttendanceSheet 
          group={group}
          session={session}
          students={students}
          attendance={attendance}
          onBack={handleBackToGroupDetails}
          onUpdateAttendance={onUpdateAttendance}
          onUpdateSession={onUpdateSession}
        />
      );
    }
  }

  // 2. Group Details View (Middle Level)
  if (selectedGroupId) {
    const group = groups.find(g => g.id === selectedGroupId);
    const groupSessions = sessions.filter(s => s.groupId === selectedGroupId);

    if (group) {
      return (
        <GroupDetails 
          group={group}
          sessions={groupSessions}
          students={students}
          onBack={handleBackToGroups}
          onSessionClick={handleSessionSelect}
          onAddSession={onAddSession}
          onUpdateSession={onUpdateSession}
          onUpdateGroup={onAddGroup}
        />
      );
    }
  }

  // 3. Group List View (Root Level)
  return (
    <>
        <GroupList 
          groups={groups} 
          onGroupClick={handleGroupSelect} 
          onAddGroupClick={() => setIsAddGroupModalOpen(true)}
        />

        {/* Create Group Modal */}
        {isAddGroupModalOpen && (
            <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
                <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200">
                    <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                        <h3 className="text-xl font-bold text-slate-800">إنشاء مجموعة جديدة</h3>
                        <button onClick={() => setIsAddGroupModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                            <X size={24} />
                        </button>
                    </div>
                    <form onSubmit={handleCreateGroup} className="p-6 space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">اسم المجموعة</label>
                            <input 
                                required
                                placeholder="مثال: مجموعة التفوق - 3 ثانوي"
                                className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                                value={newGroupForm.name}
                                onChange={e => setNewGroupForm({...newGroupForm, name: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">المادة</label>
                            <input 
                                required
                                placeholder="مثال: لغة عربية"
                                className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                                value={newGroupForm.subject}
                                onChange={e => setNewGroupForm({...newGroupForm, subject: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">المدرس المسؤول</label>
                            <select 
                                required
