import React, { useState } from 'react';
import { Transaction } from '../types';
import { CURRENCY } from '../constants';
import { TrendingUp, TrendingDown, Calendar, FileSpreadsheet, Search, Filter, ChevronDown, ChevronUp, RotateCcw, X } from 'lucide-react';

interface FinancialsProps {
  transactions: Transaction[];
  onAddTransaction?: (transaction: Transaction) => void;
}

export const Financials: React.FC<FinancialsProps> = ({ transactions, onAddTransaction }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'income' | 'expense'>('all');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'income' | 'expense'>('income');
  const [form, setForm] = useState({
      amount: '',
      category: '',
      description: '',
      notes: ''
  });

  // Filter transactions based on criteria
  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = 
      t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
      t.category.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (t.notes && t.notes.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesType = filterType === 'all' || t.type === filterType;

    const matchesStartDate = !startDate || t.date >= startDate;
    const matchesEndDate = !endDate || t.date <= endDate;

    return matchesSearch && matchesType && matchesStartDate && matchesEndDate;
  });

  // Calculate filtered totals
  const totalFilteredIncome = filteredTransactions
    .filter(t => t.type === 'income')
    .reduce((sum, t) => sum + t.amount, 0);

  const totalFilteredExpense = filteredTransactions
    .filter(t => t.type === 'expense')
    .reduce((sum, t) => sum + t.amount, 0);

  const handleOpenModal = (type: 'income' | 'expense') => {
      setModalType(type);
      setForm({ amount: '', category: '', description: '', notes: '' });
      setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (!onAddTransaction) return;

      const newTransaction: Transaction = {
          id: Date.now().toString(),
          type: modalType,
          amount: parseFloat(form.amount),
          category: form.category,
          date: new Date().toISOString().split('T')[0],
          description: form.description,
          notes: form.notes
      };

      onAddTransaction(newTransaction);
      setIsModalOpen(false);
  };

  const handleExportExcel = () => {
    // Define headers
    const headers = ['التاريخ', 'الوصف', 'التصنيف', 'النوع', 'المبلغ', 'ملاحظات'];

    // Helper to escape CSV fields (handle commas and quotes)
    const escapeCsv = (field: string | number | undefined) => {
      if (field === undefined || field === null) return '""';
      const stringField = String(field);
      if (stringField.includes(',') || stringField.includes('"') || stringField.includes('\n')) {
        return `"${stringField.replace(/"/g, '""')}"`;
      }
      return stringField;
    };

    // Map filtered data to rows
    const rows = filteredTransactions.map(t => [
      escapeCsv(t.date),
      escapeCsv(t.description),
      escapeCsv(t.category),
      escapeCsv(t.type === 'income' ? 'إيراد' : 'مصروف'),
      escapeCsv(t.amount),
      escapeCsv(t.notes || '')
    ]);

    // Combine headers and rows
    const csvContent = [
      headers.join(','),
      ...rows.map(r => r.join(','))
    ].join('\n');

    // Create Blob with BOM for Arabic support in Excel
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    // Create download link
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `financial_report_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

