import React, { useState } from 'react';
import { ArrowRight, Edit2, CheckCircle, Clock, XCircle, UserPlus, StopCircle } from 'lucide-react';
import { Group, Session, Student, AttendanceRecord, AttendanceStatus } from '../../types';
import { SessionModal } from './SessionModal';

interface AttendanceSheetProps {
  group: Group;
  session: Session;
  students: Student[];
  attendance: AttendanceRecord[];
  onBack: () => void;
  onUpdateAttendance: (record: AttendanceRecord) => void;
  onUpdateSession: (session: Session) => void;
}

export const AttendanceSheet: React.FC<AttendanceSheetProps> = ({
  group,
  session,
  students,
  attendance,
  onBack,
  onUpdateAttendance,
  onUpdateSession
}) => {
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  // Filter students belonging to this group
  const groupStudents = students.filter(s => group.studentIds.includes(s.id));

  // Compute stats
  const presentCount = groupStudents.filter(s => 
    attendance.find(a => a.sessionId === session.id && a.studentId === s.id)?.status === 'present'
  ).length;

  const attendancePercentage = groupStudents.length > 0 
    ? Math.round((presentCount / groupStudents.length) * 100) 
    : 0;

  // Handlers
  const markAttendance = (studentId: string, status: AttendanceStatus) => {
    const existingRecord = attendance.find(
      a => a.sessionId === session.id && a.studentId === studentId
    );

    const record: AttendanceRecord = {
      id: existingRecord ? existingRecord.id : Date.now().toString() + Math.random(),
      sessionId: session.id,
      studentId: studentId,
      status: status,
      timestamp: new Date().toISOString()
    };

    onUpdateAttendance(record);
  };

  const markAllPresent = () => {
    group.studentIds.forEach(sid => markAttendance(sid, 'present'));
  };

  const handleEditSubmit = (data: { topic: string; date: string; startTime: string }) => {
    onUpdateSession({
      ...session,
      topic: data.topic,
      date: data.date,
      startTime: data.startTime
    });
    setIsEditModalOpen(false);
  };

  const handleEndSession = () => {
      if (window.confirm('هل أنت متأكد من إنهاء الحصة؟ سيتم حفظ سجل الحضور وإغلاق الجلسة.')) {
          onUpdateSession({
              ...session,
              status: 'completed'
          });
      }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors">
          <ArrowRight size={24} />
        </button>
        <div className="flex-1">
          <div className="flex items-center gap-3">
              <h2 className="text-2xl font-bold text-slate-800">تسجيل الحضور</h2>
              <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                  session.status === 'active' ? 'bg-green-100 text-green-700' : 
                  session.status === 'completed' ? 'bg-slate-100 text-slate-600' : 'bg-blue-100 text-blue-700'
              }`}>
                  {session.status === 'active' ? 'نشطة' : session.status === 'completed' ? 'منتهية' : 'مجدولة'}
              </span>

              {/* End Session Button */}
              {session.status === 'active' && (
                  <button 
                    onClick={handleEndSession}
                    className="bg-rose-100 text-rose-700 hover:bg-rose-200 px-3 py-1 rounded-lg text-xs font-bold flex items-center transition-colors border border-rose-200 shadow-sm"
                  >
                      <StopCircle size={14} className="ml-1" />
                      إنهاء الحصة
                  </button>
              )}

              <button 
                  onClick={() => setIsEditModalOpen(true)}
                  className="text-slate-400 hover:text-blue-600 p-1 rounded transition-colors mr-auto ml-2"
                  title="تعديل تفاصيل الحصة"
              >
                  <Edit2 size={16} />
              </button>
          </div>
          <div className="flex items-center gap-2 mt-1 text-slate-500 text-sm">
              <span className="font-medium text-blue-600">{group.name}</span>
              <span>•</span>
              <span>{session.topic || 'بدون عنوان'}</span>
              <span>•</span>
              <span>{session.date}</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Student List */}
          <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
              <div className="flex justify-between items-center mb-6">
                  <h3 className="font-bold text-slate-800">قائمة الطلاب ({groupStudents.length})</h3>
                  {groupStudents.length > 0 && session.status !== 'completed' && (
                      <button 
                          onClick={markAllPresent}
                          className="text-blue-600 text-sm font-medium hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors flex items-center"
                      >
                          <CheckCircle size={16} className="ml-1.5" />
                          تسجيل الجميع "حضور"
                      </button>
                  )}
              </div>

              {groupStudents.length === 0 ? (
                  <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-200 text-slate-500">
                    <UserPlus size={48} className="mx-auto mb-3 opacity-20" />
                    <p className="font-medium">لا يوجد طلاب في هذه المجموعة.</p>
                    <p className="text-sm mt-1">يجب إضافة طلاب إلى المجموعة أولاً لتسجيل حضورهم.</p>
                    <button 
                        onClick={onBack}
                        className="mt-4 text-blue-600 hover:underline text-sm"
                    >
                        العودة لإدارة المجموعة
                    </button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {groupStudents.map(student => {
                          const record = attendance.find(a => a.sessionId === session.id && a.studentId === student.id);
                          const status = record?.status;

                          return (
                              <div key={student.id} className="flex items-center justify-between p-3 rounded-xl border border-slate-100 hover:bg-slate-50 transition-colors">
                                  <div className="flex items-center gap-3">
                                      <div className="w-10 h-10 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-600 text-sm">
                                          {student.name.charAt(0)}
                                      </div>
                                      <div>
                                          <p className="font-semibold text-slate-800">{student.name}</p>
                                          <p className="text-xs text-slate-500">{student.phone}</p>
                                      </div>
                                  </div>
                                  <div className="flex gap-1 bg-slate-100 p-1 rounded-lg">
                                      <button 
                                          onClick={() => markAttendance(student.id, 'present')}
                                          disabled={session.status === 'completed'}
                                          className={`p-2 rounded-md transition-all ${status === 'present' ? 'bg-emerald-500 text-white shadow-sm' : 'text-slate-400 hover:text-emerald-600'} ${session.status === 'completed' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                          title="حاضر"
                                      >
                                          <CheckCircle size={20} />
                                      </button>
                                      <button 
                                          onClick={() => markAttendance(student.id, 'late')}
                                          disabled={session.status === 'completed'}
                                          className={`p-2 rounded-md transition-all ${status === 'late' ? 'bg-amber-500 text-white shadow-sm' : 'text-slate-400 hover:text-amber-600'} ${session.status === 'completed' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                          title="تأخير"
                                      >
                                          <Clock size={20} />
                                      </button>
                                      <button 
                                          onClick={() => markAttendance(student.id, 'absent')}
                                          disabled={session.status === 'completed'}
                                          className={`p-2 rounded-md transition-all ${status === 'absent' ? 'bg-rose-500 text-white shadow-sm' : 'text-slate-400 hover:text-rose-600'} ${session.status === 'completed' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                          title="غائب"
                                      >
                                          <XCircle size={20} />
                                      </button>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              )}
          </div>

          {/* Stats Sidebar */}
          <div className="space-y-6">
              <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                  <h3 className="font-bold text-slate-800 mb-4">إحصائيات الجلسة</h3>
                  <div className="space-y-4">
                      <div className="flex justify-between items-center">
                          <span className="text-slate-600 flex items-center"><CheckCircle size={16} className="ml-2 text-emerald-500"/>حضور</span>
                          <span className="font-bold text-slate-800">{presentCount}</span>
                      </div>
                       <div className="flex justify-between items-center">
                          <span className="text-slate-600 flex items-center"><XCircle size={16} className="ml-2 text-rose-500"/>غياب</span>
                          <span className="font-bold text-slate-800">
                              {groupStudents.length - groupStudents.filter(s => attendance.find(a => a.sessionId === session.id && a.studentId === s.id)).length}
                          </span>
                      </div>
                      <div className="pt-4 border-t border-slate-100">
                          <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
                              <div 
                                  className="bg-emerald-500 h-2.5 rounded-full transition-all duration-500" 
                                  style={{ width: `${attendancePercentage}%` }}
                              ></div>
                          </div>
                          <p className="text-xs text-center mt-2 text-slate-500">
                              نسبة الحضور: {attendancePercentage}%
                          </p>
                      </div>
                  </div>
              </div>

              <div className="bg-blue-50 rounded-2xl border border-blue-100 p-4">
                  <h4 className="font-bold text-blue-800 text-sm mb-2">ملاحظة سريعة</h4>
                  <p className="text-xs text-blue-600 leading-relaxed">
                      {session.status === 'completed' 
                        ? 'هذه الحصة منتهية. لا يمكن تعديل سجل الحضور.' 
                        : 'يتم حفظ حالات الحضور تلقائياً عند النقر على الأزرار.'}
                  </p>
              </div>
          </div>
      </div>

      <SessionModal 
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleEditSubmit}
        initialData={session}
        title="تعديل موعد الحصة"
        submitLabel="حفظ التعديلات"
      />
    </div>
  );
};

import React, { useState } from 'react';
import { ArrowRight, Edit2, CheckCircle, Clock, XCircle, UserPlus, StopCircle, AlertCircle, Check } from 'lucide-react';
import { Group, Session, Student, AttendanceRecord, AttendanceStatus } from '../../types';
import { SessionModal } from './SessionModal';

interface AttendanceSheetProps {
  group: Group;
  session: Session;
  students: Student[];
  attendance: AttendanceRecord[];
  onBack: () => void;
  onUpdateAttendance: (record: AttendanceRecord) => void;
  onUpdateSession: (session: Session) => void;
}

export const AttendanceSheet: React.FC<AttendanceSheetProps> = ({
  group,
  session,
  students,
  attendance,
  onBack,
  onUpdateAttendance,
  onUpdateSession
}) => {
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [showEndConfirmation, setShowEndConfirmation] = useState(false);

  // Filter students belonging to this group
  const groupStudents = students.filter(s => group.studentIds.includes(s.id));

  // Compute stats
  const presentCount = groupStudents.filter(s => 
    attendance.find(a => a.sessionId === session.id && a.studentId === s.id)?.status === 'present'
  ).length;

  const attendancePercentage = groupStudents.length > 0 
    ? Math.round((presentCount / groupStudents.length) * 100) 
    : 0;

  // Handlers
  const markAttendance = (studentId: string, status: AttendanceStatus) => {
    const existingRecord = attendance.find(
      a => a.sessionId === session.id && a.studentId === studentId
    );

    const record: AttendanceRecord = {
      id: existingRecord ? existingRecord.id : Date.now().toString() + Math.random(),
      sessionId: session.id,
      studentId: studentId,
      status: status,
      timestamp: new Date().toISOString()
    };

    onUpdateAttendance(record);
  };

  const markAllPresent = () => {
    group.studentIds.forEach(sid => markAttendance(sid, 'present'));
  };

  const handleEditSubmit = (data: { topic: string; date: string; startTime: string }) => {
    onUpdateSession({
      ...session,
      topic: data.topic,
      date: data.date,
      startTime: data.startTime
    });
    setIsEditModalOpen(false);
  };

  const confirmEndSession = () => {
      onUpdateSession({
          ...session,
          status: 'completed'
      });
      setShowEndConfirmation(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      {/* Header */}
      <div className="flex items-center gap-4 mb-6">
        <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-lg text-slate-500 transition-colors">
          <ArrowRight size={24} />
        </button>
        <div className="flex-1">
          <div className="flex flex-wrap items-center gap-3">
              <h2 className="text-2xl font-bold text-slate-800">تسجيل الحضور</h2>
              <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                  session.status === 'active' ? 'bg-green-100 text-green-700' : 
                  session.status === 'completed' ? 'bg-slate-100 text-slate-600' : 'bg-blue-100 text-blue-700'
              }`}>
                  {session.status === 'active' ? 'نشطة' : session.status === 'completed' ? 'منتهية' : 'مجدولة'}
              </span>

              {/* End Session Button with Inline Confirmation */}
              {session.status === 'active' && (
                  <div className="flex items-center gap-2 mr-2">
                      {!showEndConfirmation ? (
                          <button 
                            type="button"
                            onClick={() => setShowEndConfirmation(true)}
                            className="bg-rose-100 text-rose-700 hover:bg-rose-200 px-4 py-1.5 rounded-lg text-xs font-bold flex items-center transition-colors border border-rose-200 shadow-sm"
                          >
                              <StopCircle size={14} className="ml-1" />
                              إنهاء الحصة
                          </button>
                      ) : (
                          <div className="flex items-center gap-2 bg-rose-50 p-1 rounded-lg border border-rose-100 animate-in fade-in zoom-in duration-200">
                              <span className="text-xs text-rose-700 font-medium px-2">تأكيد الإنهاء؟</span>
                              <button 
                                type="button"
                                onClick={confirmEndSession}
                                className="bg-rose-600 text-white px-3 py-1 rounded-md text-xs font-bold hover:bg-rose-700 transition-colors"
                              >
                                  نعم
                              </button>
                              <button 
                                type="button"
                                onClick={() => setShowEndConfirmation(false)}
                                className="bg-white text-slate-600 px-3 py-1 rounded-md text-xs font-bold hover:bg-slate-50 border border-slate-200 transition-colors"
                              >
                                  لا
                              </button>
                          </div>
                      )}
                  </div>
              )}

              <button 
                  onClick={() => setIsEditModalOpen(true)}
                  className="text-slate-400 hover:text-blue-600 p-2 rounded-lg transition-colors mr-auto bg-slate-50 hover:bg-blue-50"
                  title="تعديل تفاصيل الحصة"
              >
                  <Edit2 size={18} />
              </button>
          </div>
          <div className="flex items-center gap-2 mt-2 text-slate-500 text-sm">
              <span className="font-medium text-blue-600">{group.name}</span>
              <span className="text-slate-300">•</span>
              <span>{session.topic || 'بدون عنوان'}</span>
              <span className="text-slate-300">•</span>
              <span className="dir-ltr">{session.date}</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Student List */}
          <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
              <div className="flex justify-between items-center mb-6">
                  <h3 className="font-bold text-slate-800">قائمة الطلاب ({groupStudents.length})</h3>
                  {groupStudents.length > 0 && session.status !== 'completed' && (
                      <button 
                          onClick={markAllPresent}
                          className="text-blue-600 text-sm font-medium hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors flex items-center"
                      >
                          <CheckCircle size={16} className="ml-1.5" />
                          تسجيل الجميع "حضور"
                      </button>
                  )}
              </div>

              {groupStudents.length === 0 ? (
                  <div className="text-center py-12 bg-slate-50 rounded-xl border border-dashed border-slate-200 text-slate-500">
                    <UserPlus size={48} className="mx-auto mb-3 opacity-20" />
                    <p className="font-medium">لا يوجد طلاب في هذه المجموعة.</p>
                    <p className="text-sm mt-1">يجب إضافة طلاب إلى المجموعة أولاً لتسجيل حضورهم.</p>
                    <button 
                        onClick={onBack}
                        className="mt-4 text-blue-600 hover:underline text-sm"
                    >
                        العودة لإدارة المجموعة
                    </button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {groupStudents.map(student => {
                          const record = attendance.find(a => a.sessionId === session.id && a.studentId === student.id);
                          const status = record?.status;

                          return (
                              <div key={student.id} className="flex items-center justify-between p-3 rounded-xl border border-slate-100 hover:bg-slate-50 transition-colors">
                                  <div className="flex items-center gap-3">
                                      <div className="w-10 h-10 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-600 text-sm">
                                          {student.name.charAt(0)}
                                      </div>
                                      <div>
                                          <p className="font-semibold text-slate-800">{student.name}</p>
                                          <p className="text-xs text-slate-500">{student.phone}</p>
                                      </div>
                                  </div>
                                  <div className="flex gap-1 bg-slate-100 p-1 rounded-lg">
                                      <button 
                                          onClick={() => markAttendance(student.id, 'present')}
                                          disabled={session.status === 'completed'}
                                          className={`p-2 rounded-md transition-all ${status === 'present' ? 'bg-emerald-500 text-white shadow-sm' : 'text-slate-400 hover:text-emerald-600'} ${session.status === 'completed' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                          title="حاضر"
                                      >
                                          <CheckCircle size={20} />
                                      </button>
                                      <button 
                                          onClick={() => markAttendance(student.id, 'late')}
                                          disabled={session.status === 'completed'}
                                          className={`p-2 rounded-md transition-all ${status === 'late' ? 'bg-amber-500 text-white shadow-sm' : 'text-slate-400 hover:text-amber-600'} ${session.status === 'completed' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                          title="تأخير"
                                      >
                                          <Clock size={20} />
                                      </button>
                                      <button 
                                          onClick={() => markAttendance(student.id, 'absent')}
                                          disabled={session.status === 'completed'}
                                          className={`p-2 rounded-md transition-all ${status === 'absent' ? 'bg-rose-500 text-white shadow-sm' : 'text-slate-400 hover:text-rose-600'} ${session.status === 'completed' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                          title="غائب"
                                      >
                                          <XCircle size={20} />
                                      </button>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              )}
          </div>

          {/* Stats Sidebar */}
          <div className="space-y-6">
              <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                  <h3 className="font-bold text-slate-800 mb-4">إحصائيات الجلسة</h3>
                  <div className="space-y-4">
                      <div className="flex justify-between items-center">
                          <span className="text-slate-600 flex items-center"><CheckCircle size={16} className="ml-2 text-emerald-500"/>حضور</span>
                          <span className="font-bold text-slate-800">{presentCount}</span>
                      </div>
                       <div className="flex justify-between items-center">
                          <span className="text-slate-600 flex items-center"><XCircle size={16} className="ml-2 text-rose-500"/>غياب</span>
                          <span className="font-bold text-slate-800">
                              {groupStudents.length - groupStudents.filter(s => attendance.find(a => a.sessionId === session.id && a.studentId === s.id)).length}
                          </span>
                      </div>
                      <div className="pt-4 border-t border-slate-100">
                          <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
                              <div 
                                  className="bg-emerald-500 h-2.5 rounded-full transition-all duration-500" 
                                  style={{ width: `${attendancePercentage}%` }}
                              ></div>
                          </div>
                          <p className="text-xs text-center mt-2 text-slate-500">
                              نسبة الحضور: {attendancePercentage}%
                          </p>
                      </div>
                  </div>
              </div>

              <div className={`rounded-2xl border p-4 transition-colors ${
                  session.status === 'completed' ? 'bg-slate-50 border-slate-200' : 'bg-blue-50 border-blue-100'
              }`}>
                  <h4 className={`font-bold text-sm mb-2 flex items-center ${
                      session.status === 'completed' ? 'text-slate-700' : 'text-blue-800'
                  }`}>
                      <AlertCircle size={16} className="ml-2" />
                      حالة الحصة
                  </h4>
                  <p className={`text-xs leading-relaxed ${
                       session.status === 'completed' ? 'text-slate-600' : 'text-blue-600'
                  }`}>
                      {session.status === 'completed' 
                        ? 'تم إنهاء هذه الحصة. تم إغلاق سجل الحضور ولا يمكن إجراء تعديلات إضافية.' 
                        : 'الحصة جارية الآن. يتم حفظ حالات الحضور تلقائياً. قم بإنهاء الحصة عند الانتهاء لإغلاق السجل.'}
                  </p>
                  {session.status === 'completed' && (
                      <div className="mt-3 flex items-center justify-center text-emerald-600 font-bold text-sm bg-white p-2 rounded-lg border border-slate-100 shadow-sm">
                          <Check size={16} className="ml-1" />
                          مكتملة
                      </div>
                  )}
              </div>
          </div>
      </div>

      <SessionModal 
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleEditSubmit}
        initialData={session}
        title="تعديل موعد الحصة"
        submitLabel="حفظ التعديلات"
      />
    </div>
  );
};

import React, { useState } from 'react';
import { Transaction } from '../types';
import { CURRENCY } from '../constants';
import { TrendingUp, TrendingDown, Calendar, FileSpreadsheet, Search, Filter, ChevronDown, ChevronUp, RotateCcw, X } from 'lucide-react';

interface FinancialsProps {
  transactions: Transaction[];
  onAddTransaction?: (transaction: Transaction) => void;
}

export const Financials: React.FC<FinancialsProps> = ({ transactions, onAddTransaction }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false);
  const [filterType, setFilterType] = useState<'all' | 'income' | 'expense'>('all');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'income' | 'expense'>('income');
  const [form, setForm] = useState({
      amount: '',
      category: '',
      description: '',
      notes: ''
  });

  // Filter transactions based on criteria
  const filteredTransactions = transactions.filter(t => {
    const matchesSearch = 
      t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
      t.category.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (t.notes && t.notes.toLowerCase().includes(searchTerm.toLowerCase()));

    const matchesType = filterType === 'all' || t.type === filterType;

    const matchesStartDate = !startDate || t.date >= startDate;
    const matchesEndDate = !endDate || t.date <= endDate;

    return matchesSearch && matchesType && matchesStartDate && matchesEndDate;
  });

  // Calculate filtered totals
  const totalFilteredIncome = filteredTransactions
    .filter(t => t.type === 'income')
    .reduce((sum, t) => sum + t.amount, 0);

  const totalFilteredExpense = filteredTransactions
    .filter(t => t.type === 'expense')
    .reduce((sum, t) => sum + t.amount, 0);

  const handleOpenModal = (type: 'income' | 'expense') => {
      setModalType(type);
      setForm({ amount: '', category: '', description: '', notes: '' });
      setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (!onAddTransaction) return;

      const newTransaction: Transaction = {
          id: Date.now().toString(),
          type: modalType,
          amount: parseFloat(form.amount),
          category: form.category,
          date: new Date().toISOString().split('T')[0],
          description: form.description,
          notes: form.notes
      };

      onAddTransaction(newTransaction);
      setIsModalOpen(false);
  };

  const handleExportExcel = () => {
    // Define headers
    const headers = ['التاريخ', 'الوصف', 'التصنيف', 'النوع', 'المبلغ', 'ملاحظات'];

    // Helper to escape CSV fields (handle commas and quotes)
    const escapeCsv = (field: string | number | undefined) => {
      if (field === undefined || field === null) return '""';
      const stringField = String(field);
      if (stringField.includes(',') || stringField.includes('"') || stringField.includes('\n')) {
        return `"${stringField.replace(/"/g, '""')}"`;
      }
      return stringField;
    };

    // Map filtered data to rows
    const rows = filteredTransactions.map(t => [
      escapeCsv(t.date),
      escapeCsv(t.description),
      escapeCsv(t.category),
      escapeCsv(t.type === 'income' ? 'إيراد' : 'مصروف'),
      escapeCsv(t.amount),
      escapeCsv(t.notes || '')
    ]);

    // Combine headers and rows
    const csvContent = [
      headers.join(','),
      ...rows.map(r => r.join(','))
    ].join('\n');

    // Create Blob with BOM for Arabic support in Excel
    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    // Create download link
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `financial_report_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const resetFilters = () => {
    setSearchTerm('');
    setFilterType('all');
    setStartDate('');
    setEndDate('');
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">الإدارة المالية</h2>
          <p className="text-slate-500 mt-1">تتبع الإيرادات والمصروفات وصافي الربح</p>
        </div>
        <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={handleExportExcel}
              className="bg-white border border-slate-300 text-slate-700 px-4 py-2 rounded-lg text-sm font-medium hover:bg-slate-50 flex items-center transition-colors shadow-sm whitespace-nowrap"
            >
                <FileSpreadsheet size={16} className="ml-2"/>
                تصدير Excel
            </button>
            <button 
                onClick={() => handleOpenModal('income')}
                className="bg-emerald-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-emerald-700 flex items-center shadow-sm shadow-emerald-600/20 whitespace-nowrap"
            >
                <TrendingUp size={16} className="ml-2"/>
                إضافة إيراد
            </button>
            <button 
                onClick={() => handleOpenModal('expense')}
                className="bg-rose-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-rose-700 flex items-center shadow-sm shadow-rose-600/20 whitespace-nowrap"
            >
                <TrendingDown size={16} className="ml-2"/>
                إضافة مصروف
            </button>
        </div>
      </div>

      {/* Filter Bar */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col gap-4">
        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
                <input 
                    type="text" 
                    placeholder="بحث في المعاملات (الوصف، التصنيف، الملاحظات)..." 
                    className="w-full pl-4 pr-10 py-2.5 rounded-lg border border-slate-200 focus:outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-500 transition-all"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>
             <button 
                onClick={() => setIsFilterPanelOpen(!isFilterPanelOpen)}
                className={`flex items-center px-4 py-2.5 border rounded-lg transition-colors ${
                    isFilterPanelOpen || filterType !== 'all' || startDate || endDate
                    ? 'bg-blue-50 border-blue-200 text-blue-700' 
                    : 'border-slate-200 text-slate-600 hover:bg-slate-50'
                }`}
            >
                <Filter size={18} className="ml-2" />
                تصفية
                {isFilterPanelOpen ? <ChevronUp size={16} className="mr-2"/> : <ChevronDown size={16} className="mr-2"/>}
            </button>
        </div>

        {/* Filter Panel */}
         {isFilterPanelOpen && (
            <div className="pt-4 border-t border-slate-100 grid grid-cols-1 md:grid-cols-4 gap-4 animate-in slide-in-from-top-2 duration-200">
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">نوع المعاملة</label>
                    <select 
                        value={filterType}
                        onChange={(e) => setFilterType(e.target.value as any)}
                        className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white text-slate-900 text-sm"
                    >
                        <option value="all">الكل</option>
                        <option value="income">إيرادات</option>
                        <option value="expense">مصروفات</option>
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">من تاريخ</label>
                    <input 
                        type="date" 
                        value={startDate}
                        onChange={(e) => setStartDate(e.target.value)}
                        className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm text-slate-900"
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">إلى تاريخ</label>
                    <input 
                        type="date" 
                        value={endDate}
                        onChange={(e) => setEndDate(e.target.value)}
                        className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm text-slate-900"
                    />
                </div>
                <div className="flex items-end">
                    <button 
                        onClick={resetFilters}
                        className="w-full p-2.5 bg-slate-100 text-slate-600 rounded-lg hover:bg-slate-200 transition-colors flex items-center justify-center font-medium text-sm"
                    >
                        <RotateCcw size={16} className="ml-2" />
                        إعادة تعيين
                    </button>
                </div>
            </div>
        )}
      </div>

      {/* Summary Cards for Filtered View */}
      {(filterType !== 'all' || searchTerm || startDate || endDate) && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-in fade-in duration-300">
              <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
                  <p className="text-sm text-emerald-600 font-medium">مجموع الإيرادات (المصفاة)</p>
                  <p className="text-xl font-bold text-emerald-700">{totalFilteredIncome} {CURRENCY}</p>
              </div>
              <div className="bg-rose-50 p-4 rounded-xl border border-rose-100">
                  <p className="text-sm text-rose-600 font-medium">مجموع المصروفات (المصفاة)</p>
                  <p className="text-xl font-bold text-rose-700">{totalFilteredExpense} {CURRENCY}</p>
              </div>
              <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
                  <p className="text-sm text-blue-600 font-medium">الصافي (المصفى)</p>
                  <p className={`text-xl font-bold ${totalFilteredIncome - totalFilteredExpense >= 0 ? 'text-blue-700' : 'text-rose-700'}`}>
                      {totalFilteredIncome - totalFilteredExpense} {CURRENCY}
                  </p>
              </div>
          </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
            <h3 className="font-bold text-slate-700">سجل المعاملات {filteredTransactions.length !== transactions.length ? `(${filteredTransactions.length})` : ''}</h3>
        </div>
        <table className="w-full text-right">
            <thead className="bg-white text-slate-500 font-medium text-sm">
                <tr>
                    <th className="p-4 border-b">المعاملة</th>
                    <th className="p-4 border-b">التصنيف</th>
                    <th className="p-4 border-b">التاريخ</th>
                    <th className="p-4 border-b">المبلغ</th>
                </tr>
            </thead>
            <tbody>
                {filteredTransactions.length === 0 ? (
                    <tr>
                        <td colSpan={4} className="p-8 text-center text-slate-400">لا توجد معاملات مطابقة للبحث</td>
                    </tr>
                ) : (
                    filteredTransactions.map(t => (
                        <tr key={t.id} className="hover:bg-slate-50">
                            <td className="p-4 border-b border-slate-50">
                                <div className="font-medium text-slate-800">{t.description}</div>
                                {t.studentId && <div className="text-xs text-slate-400">مرتبط بطالب</div>}
                                {t.notes && <div className="text-xs text-slate-500 mt-1 italic">{t.notes}</div>}
                            </td>
                            <td className="p-4 border-b border-slate-50">
                                <span className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-xs">
                                    {t.category}
                                </span>
                            </td>
                            <td className="p-4 border-b border-slate-50 text-slate-500 text-sm flex items-center">
                                <Calendar size={14} className="ml-1"/>
                                {t.date}
                            </td>
                            <td className={`p-4 border-b border-slate-50 font-bold ${t.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                                {t.type === 'income' ? '+' : '-'} {t.amount} {CURRENCY}
                            </td>
                        </tr>
                    ))
                )}
            </tbody>
        </table>
      </div>

       {/* Add Transaction Modal */}
       {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-xl font-bold text-slate-800">
                  {modalType === 'income' ? 'إضافة إيراد جديد' : 'إضافة مصروف جديد'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">المبلغ ({CURRENCY})</label>
                <input 
                    type="number" 
                    required 
                    className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none font-bold text-lg text-slate-900 bg-white" 
                    placeholder="0.00"
                    value={form.amount}
                    onChange={(e) => setForm({...form, amount: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">الوصف</label>
                <input 
                    required 
                    className="w-full p-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-slate-900 bg-white" 
                    placeholder={modalType === 'income' ? "مثال: بيع كتب خارجية" : "مثال: فاتورة كهرباء"}
                    value={form.description}
                    onChange={(e) => setForm({...form, description: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">التصنيف</label>
                <select 
                    required
