                <div className={`p-4 rounded-xl border flex items-center gap-3 ${
                    status.type === 'success' ? 'bg-emerald-50 border-emerald-100 text-emerald-700' :
                    status.type === 'error' ? 'bg-red-50 border-red-100 text-red-700' :
