import React, { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './views/Dashboard';
import { Students } from './views/Students';
import { Financials } from './views/Financials';
import { Groups } from './views/Groups';
import { Teachers } from './views/Teachers';
import { Reports } from './views/Reports';
import { Settings } from './views/Settings';
import { Login } from './views/Login';
import { Student, Session, AttendanceRecord, Transaction, Group, Teacher, UserProfile } from './types';
import { db } from './services/Database';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [isLoadingAuth, setIsLoadingAuth] = useState(true);

  const [activeView, setActiveView] = useState('dashboard');
  const [isDbReady, setIsDbReady] = useState(false);

  // State populated from DB
  const [students, setStudents] = useState<Student[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [sessions, setSessions] = useState<Session[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [teachers, setTeachers] = useState<Teacher[]>([]);

  // Check for saved session
  useEffect(() => {
    const savedUser = localStorage.getItem('educenter_user');
    if (savedUser) {
        try {
            setCurrentUser(JSON.parse(savedUser));
        } catch (e) {
            console.error("Invalid user session");
            localStorage.removeItem('educenter_user');
        }
    }
    setIsLoadingAuth(false);
  }, []);

  // Initialize DB on mount
  useEffect(() => {
    const initData = async () => {
        await db.init();
        refreshData();
        setIsDbReady(true);
    };
    initData();
  }, []);

  const handleLogin = (user: UserProfile) => {
      setCurrentUser(user);
      localStorage.setItem('educenter_user', JSON.stringify(user));
  };

  const handleLogout = () => {
      setCurrentUser(null);
      localStorage.removeItem('educenter_user');
      setActiveView('dashboard'); // Reset view on logout
  };

  const refreshData = () => {
      setStudents(db.getAllStudents());
      setTransactions(db.getAllTransactions());
      setGroups(db.getAllGroups());
      setSessions(db.getAllSessions());
      setAttendance(db.getAllAttendance());
      setTeachers(db.getAllTeachers());
  };

  const handleAddStudent = (newStudent: Student) => {
    db.addStudent(newStudent);
    refreshData();
  };

  const handleDeleteStudent = (id: string) => {
    db.deleteStudent(id);
    refreshData();
  };

  const handleAddSession = (newSession: Session) => {
    db.addSession(newSession);
    refreshData();
  };

  const handleUpdateSession = (updatedSession: Session) => {
    db.addSession(updatedSession); // addSession uses REPLACE
    refreshData();
  };

  const handleUpdateAttendance = (record: AttendanceRecord) => {
    db.addAttendance(record);
    refreshData();
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    db.addTransaction(newTransaction);

    // Update Student Balance logic via DB
    if (newTransaction.studentId) {
        // Fetch fresh data from DB to ensure balance is accurate
        const currentStudents = db.getAllStudents();
        const student = currentStudents.find(s => s.id === newTransaction.studentId);

        if (student) {
            const change = newTransaction.type === 'income' ? newTransaction.amount : -newTransaction.amount;
            const newBalance = student.balance + change;
            db.updateStudentBalance(student.id, newBalance);
        }
    }
    refreshData();
  };

  const handleAddTeacher = (teacher: Teacher) => {
    db.addTeacher(teacher);
    refreshData();
  };

  const handleDeleteTeacher = (id: string) => {
    db.deleteTeacher(id);
    refreshData();
  };

  const handleAddGroup = (group: Group) => {
    db.addGroup(group);
    refreshData();
  };

  const handleDeleteGroup = (id: string) => {
    db.deleteGroup(id);
    refreshData();
  };

  const renderContent = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard students={students} transactions={transactions} />;
      case 'students':
        return (
            <Students 
                students={students} 
                transactions={transactions}
                onAddStudent={handleAddStudent} 
                onDeleteStudent={handleDeleteStudent}
                onAddTransaction={handleAddTransaction}
            />
        );
      case 'teachers':
        return (
          <Teachers 
            teachers={teachers} 
            groups={groups}
            sessions={sessions}
            transactions={transactions}
            attendance={attendance}
            onAddTeacher={handleAddTeacher}
            onDeleteTeacher={handleDeleteTeacher}
            onAddTransaction={handleAddTransaction}
          />
        );
      case 'groups':
        return (
          <Groups 
            groups={groups} 
            students={students} 
            sessions={sessions} 
            attendance={attendance}
            teachers={teachers}
            onAddSession={handleAddSession}
            onUpdateSession={handleUpdateSession}
            onUpdateAttendance={handleUpdateAttendance}
            onAddGroup={handleAddGroup}
            onDeleteGroup={handleDeleteGroup}
          />
        );
      case 'financials':
        return (
          <Financials 
            transactions={transactions} 
            onAddTransaction={handleAddTransaction}
          />
        );
      case 'reports':
        return (
          <Reports 
             students={students}
             teachers={teachers}
             transactions={transactions}
             attendance={attendance}
             groups={groups}
             sessions={sessions}
          />
        );
      case 'settings':
        return <Settings />;
      default:
        return <Dashboard students={students} transactions={transactions} />;
    }
  };

  // 1. Loading State
  if (isLoadingAuth || (!isDbReady && currentUser)) {
      return (
          <div className="h-screen w-screen flex flex-col items-center justify-center bg-slate-50 text-slate-600 gap-4">
              <Loader2 className="animate-spin text-blue-600" size={48} />
              <p className="font-medium">
                  {!isDbReady ? 'جاري تحميل قاعدة البيانات...' : 'جاري التحقق من الدخول...'}
              </p>
          </div>
      );
  }

  // 2. Login View
  if (!currentUser) {
      return <Login onLogin={handleLogin} />;
  }

  // 3. Main App View
  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <Sidebar 
          activeView={activeView} 
          setActiveView={setActiveView} 
          currentUser={currentUser}
          onLogout={handleLogout}
      />

      {/* Main Content Area */}
      <main className="flex-1 mr-64 h-screen overflow-y-auto p-8 relative">
        <header className="flex justify-between items-center mb-8 print:hidden">
          <div>
             {/* Breadcrumbs or Title could go here */}
          </div>
          <div className="flex items-center gap-4">
             <div className="text-left hidden md:block">
                <p className="text-sm font-bold text-slate-700">{currentUser.name}</p>
                <p className="text-xs text-slate-500">نشط الآن</p>
             </div>
             <div className="w-10 h-10 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
                 {currentUser.avatar ? (
                     <img src={currentUser.avatar} alt="User" />
                 ) : (
                    <div className="w-full h-full flex items-center justify-center bg-blue-100 text-blue-600 font-bold">
                        {currentUser.name.charAt(0)}
                    </div>
                 )}
             </div>
          </div>
        </header>

        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
           {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { db } from '../services/Database';
import { Save, Upload, Database, AlertCircle, Check, Download, Info } from 'lucide-react';

export const Settings: React.FC = () => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [status, setStatus] = useState<{type: 'success' | 'error' | 'loading' | null, message: string}>({ type: null, message: '' });

    const handleBackup = () => {
        try {
            const data = db.exportDatabase();
            if (data) {
                const blob = new Blob([data], { type: 'application/x-sqlite3' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `educenter_backup_${new Date().toISOString().split('T')[0]}.db`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);
                setStatus({ type: 'success', message: 'تم تحميل ملف النسخ الاحتياطي بنجاح' });
            } else {
                setStatus({ type: 'error', message: 'فشل في تصدير قاعدة البيانات' });
            }
        } catch (e) {
            console.error(e);
            setStatus({ type: 'error', message: 'حدث خطأ أثناء النسخ الاحتياطي' });
        }
    };

    const handleRestoreTrigger = () => {
        if (fileInputRef.current) {
            fileInputRef.current.click();
        }
    };

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!window.confirm('تحذير: استعادة قاعدة البيانات ستقوم باستبدال كافة البيانات الحالية. هل أنت متأكد من الاستمرار؟')) {
            if(fileInputRef.current) fileInputRef.current.value = '';
            return;
        }

        try {
            setStatus({ type: 'loading', message: 'جاري استعادة البيانات...' });
            await db.importDatabase(file);
            setStatus({ type: 'success', message: 'تم استعادة البيانات بنجاح. جاري تحديث النظام...' });
            setTimeout(() => {
                window.location.reload();
            }, 1500);
        } catch (err) {
            console.error(err);
            setStatus({ type: 'error', message: 'فشل في قراءة ملف قاعدة البيانات. تأكد من صحة الملف.' });
        }
    };

    return (
        <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div>
                <h2 className="text-2xl font-bold text-slate-800">إعدادات النظام</h2>
                <p className="text-slate-500 mt-1">النسخ الاحتياطي، استعادة البيانات، وإدارة النظام</p>
            </div>

            {status.type && (
                <div className={`p-4 rounded-xl border flex items-center gap-3 ${
                    status.type === 'success' ? 'bg-emerald-50 border-emerald-100 text-emerald-700' :
                    status.type === 'error' ? 'bg-red-50 border-red-100 text-red-700' :
                    'bg-blue-50 border-blue-100 text-blue-700'
                }`}>
                    {status.type === 'success' && <Check size={20} />}
                    {status.type === 'error' && <AlertCircle size={20} />}
                    {status.type === 'loading' && <div className="w-5 h-5 border-2 border-current border-t-transparent rounded-full animate-spin"></div>}
                    <span className="font-medium">{status.message}</span>
                </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* Backup Card */}
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                    <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-xl flex items-center justify-center mb-4">
                        <Download size={24} />
                    </div>
                    <h3 className="text-lg font-bold text-slate-800 mb-2">النسخ الاحتياطي</h3>
                    <p className="text-slate-500 text-sm mb-6 leading-relaxed">
                        قم بتحميل نسخة كاملة من قاعدة البيانات (ملف .db) وحفظها على جهازك الشخصي لضمان عدم ضياع البيانات.
                    </p>
                    <button 
                        onClick={handleBackup}
                        className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-medium transition-colors flex items-center justify-center gap-2 shadow-lg shadow-blue-600/20"
                    >
                        <Save size={18} />
                        تحميل نسخة احتياطية
                    </button>
                </div>

                {/* Restore Card */}
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                    <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-xl flex items-center justify-center mb-4">
                        <Upload size={24} />
                    </div>
                    <h3 className="text-lg font-bold text-slate-800 mb-2">استعادة البيانات</h3>
                    <p className="text-slate-500 text-sm mb-6 leading-relaxed">
                        استرجع البيانات من ملف نسخ احتياطي سابق. سيؤدي هذا إلى استبدال جميع البيانات الحالية.
                    </p>
                    <input 
                        type="file" 
                        accept=".db,.sqlite" 
                        ref={fileInputRef} 
                        className="hidden" 
                        onChange={handleFileChange}
                    />
                    <button 
                        onClick={handleRestoreTrigger}
                        className="w-full py-3 bg-white border border-slate-200 hover:border-emerald-500 hover:bg-emerald-50 text-slate-700 hover:text-emerald-700 rounded-xl font-medium transition-all flex items-center justify-center gap-2"
                    >
                        <Upload size={18} />
                        اختيار ملف للاستعادة
                    </button>
                </div>
            </div>

            <div className="w-full">
                 {/* System Info */}
                 <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                    <div className="flex items-center gap-3 mb-6">
                        <Database size={20} className="text-slate-400" />
                        <h3 className="font-bold text-slate-800">حالة النظام والبيانات</h3>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="flex items-center gap-3 p-4 bg-slate-50 rounded-xl border border-slate-100">
                            <Info size={20} className="text-blue-500 shrink-0" />
